# --- ForzeOS: Safe tkinter scheduling & bgerror guards ---
# Prevent "invalid command name" errors when Tk widgets schedule callbacks
# that execute after the application or a window has been destroyed. We
# monkeypatch the `after`, `after_idle`, and `after_cancel` methods on
# tkinter.Misc to track scheduled IDs and provide helpers to cancel them.
_FORZEOS_AFTER_REGISTRY = {}  # widget -> set(of after ids)

# Save original methods so we can call them
_FORZEOS__orig_after = getattr(_tk.Misc, 'after', None)
_FORZEOS__orig_after_idle = getattr(_tk.Misc, 'after_idle', None)
_FORZEOS__orig_after_cancel = getattr(_tk.Misc, 'after_cancel', None)

def _forzeos_after(self, ms, func=None, *f_args, **f_kwargs):
    # Support both forms: after(ms, func, ...) and after(ms) (sleep-like)
    if func is None:
        return _FORZEOS__orig_after(self, ms)
    # Wrap callback to ensure we remove tracked id when it runs. Use a
    # mutable container to hold the assigned id so the wrapper can refer
    # to it reliably regardless of execution timing.
    container = {'id': None}

    def _wrapped(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception:
            logger.exception('Exception in scheduled callback', exc_info=True)
        finally:
            try:
                _id = container.get('id')
                ids = _FORZEOS_AFTER_REGISTRY.get(self)
                if ids and _id in ids:
                    ids.discard(_id)
            except Exception:
                pass

    _id = _FORZEOS__orig_after(self, ms, _wrapped, *f_args, **f_kwargs)
    container['id'] = _id
    _FORZEOS_AFTER_REGISTRY.setdefault(self, set()).add(_id)
    return _id

def _forzeos_after_idle(self, func, *f_args, **f_kwargs):
    container = {'id': None}

    def _wrapped(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except Exception:
            logger.exception('Exception in after_idle callback', exc_info=True)
        finally:
            try:
                _id = container.get('id')
                ids = _FORZEOS_AFTER_REGISTRY.get(self)
                if ids and _id in ids:
                    ids.discard(_id)
            except Exception:
                pass

    _id = _FORZEOS__orig_after_idle(self, _wrapped, *f_args, **f_kwargs)
    container['id'] = _id
    _FORZEOS_AFTER_REGISTRY.setdefault(self, set()).add(_id)
    return _id

def _forzeos_after_cancel(self, aid):
    try:
        # remove from registry if present, then call original
        try:
            ids = _FORZEOS_AFTER_REGISTRY.get(self)
            if ids:
                ids.discard(aid)
        except Exception:
            pass
        return _FORZEOS__orig_after_cancel(self, aid)
    except Exception:
        # ignore cancellation errors (widget may already be destroyed)
        return None

# Apply monkeypatches if originals exist
try:
    if _FORZEOS__orig_after is not None:
        _tk.Misc.after = _forzeos_after
    if _FORZEOS__orig_after_idle is not None:
        _tk.Misc.after_idle = _forzeos_after_idle
    if _FORZEOS__orig_after_cancel is not None:
        _tk.Misc.after_cancel = _forzeos_after_cancel
except Exception:
    pass

def forzeos_cancel_all_for_widget(widget):
    ids = list(_FORZEOS_AFTER_REGISTRY.get(widget, ()))
    for aid in ids:
        try:
            if _FORZEOS__orig_after_cancel is not None:
                _FORZEOS__orig_after_cancel(widget, aid)
        except Exception:
            pass
    _FORZEOS_AFTER_REGISTRY.pop(widget, None)

def forzeos_cancel_all():
    for widget, ids in list(_FORZEOS_AFTER_REGISTRY.items()):
        for aid in list(ids):
            try:
                if _FORZEOS__orig_after_cancel is not None:
                    _FORZEOS__orig_after_cancel(widget, aid)
            except Exception:
                pass
    _FORZEOS_AFTER_REGISTRY.clear()

# Safe bgerror handler: avoid using Tk when it's already destroyed.
def _forzeos_safe_report_callback_exception(self, exc, val, tb):
    # Avoid any use of tkinter APIs here because the application or Tcl
    # interpreter may be partially torn down. Only log the exception so
    # it can be inspected in the log file.
    try:
        logger.error('Unhandled exception in Tk callback: %s: %s', getattr(exc, '__name__', str(exc)), val)
        logger.debug('Callback traceback:', exc_info=(exc, val, tb))
    except Exception:
        # Final fallback: ensure we never raise from the bgerror handler.
        try:
            traceback.print_exception(exc, val, tb)
        except Exception:
            pass

try:
    _tk.Tk.report_callback_exception = _forzeos_safe_report_callback_exception
except Exception:
    pass
