def start_focus(instance, aggressive: bool = False):
    """Start Focus Mode for `instance`.

    If `aggressive=True` and the native aggressive module is available, use
    the aggressive path. Otherwise fall back to the pure-Python focus mode.
    This helper centralizes the decision so UI code can present a single
    action that optionally uses the native accelerator.
    """
    if aggressive and AGGRESSIVE_FOCUS_AVAILABLE and forzeos_focus is not None:
        try:
            return forzeos_focus.enter_aggressive_focus_mode(instance)
        except Exception:
            logger.exception('Aggressive focus failed; falling back to python focus')
            try:
                return forzeos_focus.enter_focus_mode(instance)
            except Exception:
                logger.exception('Fallback python focus also failed')
                raise

    # Aggressive not requested or unavailable — use Python focus if possible
    if forzeos_focus is not None:
        return forzeos_focus.enter_focus_mode(instance)

    raise RuntimeError('Focus Mode subsystem is not available')


def show_focus_mode_dialog(instance):
    """Simple UI: ask the user whether to start aggressive Focus Mode or the
    standard Python Focus Mode. Presents a Yes/No style prompt. This is a
    convenience wrapper; callers in the UI should call this to present the
    choice to users.
    """
    try:
        import tkinter as _tk
        from tkinter import messagebox as _mb
    except Exception:
        logger.exception('tkinter not available for focus dialog')
        raise

    if forzeos_focus is None:
        _mb.showerror('Focus Mode', 'Focus Mode subsystem is not available.')
        return None

    if AGGRESSIVE_FOCUS_AVAILABLE:
        # Ask user: Yes = aggressive, No = python, Cancel = nothing
        resp = _mb.askyesno('Focus Mode', 'Start Aggressive Focus Mode? (Yes = aggressive, No = standard)')
        if resp:
            try:
                return start_focus(instance, aggressive=True)
            except Exception:
                logger.exception('Failed to start aggressive focus; trying standard')
                try:
                    return start_focus(instance, aggressive=False)
                except Exception:
                    _mb.showerror('Focus Mode', 'Failed to start Focus Mode.')
                    return None
        else:
            try:
                return start_focus(instance, aggressive=False)
            except Exception:
                _mb.showerror('Focus Mode', 'Failed to start Focus Mode.')
                logger.exception('Failed to start standard focus')
                return None
    else:
        ok = _mb.askokcancel('Focus Mode', 'Aggressive native module not available. Start standard Focus Mode?')
        if ok:
            try:
                return start_focus(instance, aggressive=False)
            except Exception:
                _mb.showerror('Focus Mode', 'Failed to start Focus Mode.')
                logger.exception('Failed to start standard focus')
                return None
        return None


def stop_focus(instance):
    """Stop any active focus mode: prefer aggressive stop when indicated.

    This calls `forzeos_focus.exit_aggressive_focus_mode` when the active
    FocusModeState indicates aggressive native was used; otherwise calls
    `forzeos_focus.exit_focus_mode`.
    """
    if forzeos_focus is None:
        logger.warning('stop_focus: forzeos_focus not available')
        return None
    try:
        state = getattr(instance, '_focus_state', None)
        if state and isinstance(state, dict):
            # defensive: older formats may store dict
            aggressive_flag = state.get('_aggressive_native')
        else:
            aggressive_flag = getattr(state, 'forzeos_saved', {}).get('_aggressive_native') if state else False

        if aggressive_flag and hasattr(forzeos_focus, 'exit_aggressive_focus_mode'):
            return forzeos_focus.exit_aggressive_focus_mode(instance)
        else:
            return forzeos_focus.exit_focus_mode(instance)
    except Exception:
        logger.exception('stop_focus failed')
        return None

# Lightweight lazy module proxy to avoid importing heavy modules at startup.
class _LazyProxy:
    def __init__(self, mod_name):
        self._mod_name = mod_name
        self._module = None
        self._failed = False
    def _load(self):
        if self._module is None and not self._failed:
            try:
                import importlib
                # prefer importlib.import_module so submodules resolve correctly
                self._module = importlib.import_module(self._mod_name)
            except Exception:
                try:
                    # fallback to __import__ for very old environments
                    self._module = __import__(self._mod_name)
                except Exception:
                    self._failed = True
                    self._module = None
            # If this is the PIL ImageTk module, wrap PhotoImage to register refs
            try:
                if self._module is not None and (self._mod_name == 'PIL.ImageTk' or self._mod_name.endswith('.ImageTk')):
                    real_photo = getattr(self._module, 'PhotoImage', None)
                    if real_photo and not getattr(real_photo, '_forze_wrapped', False):
                        def _wrapped_photo(*a, **kw):
                            img = real_photo(*a, **kw)
                            try:
                                for inst in list(FORZEOS_INSTANCES):
                                    try:
                                        if hasattr(inst, '_image_refs'):
                                            inst._image_refs.append(img)
                                    except Exception:
                                        pass
                            except Exception:
                                pass
                            return img
                        try:
                            _wrapped_photo._forze_wrapped = True
                            setattr(self._module, 'PhotoImage', _wrapped_photo)
                        except Exception:
                            pass
            except Exception:
                pass
    def __getattr__(self, item):
        self._load()
        if self._module is None:
            raise ImportError(f"Optional module '{self._mod_name}' is not available")
        return getattr(self._module, item)
    def __bool__(self):
        # True if module is available (spec exists)
        try:
            return importlib.util.find_spec(self._mod_name) is not None
        except Exception:
            return False

# Use lazy proxies for modules that can be large
psutil = _LazyProxy('psutil')
# RAM OPTIMIZATION: lightweight helper to create lazy imports on demand.
def lazy_import(mod_name):
    """Return a lazy proxy for `mod_name`. Uses existing _LazyProxy if available.

    This allows large optional modules to be referenced without paying the
    import cost until first attribute access.
    """
    try:
        # Prefer reusing existing proxies/objects if present
        g = globals()
        if mod_name in g and g.get(mod_name) is not None:
            return g.get(mod_name)
        # Use existing _LazyProxy class if defined
        if '_LazyProxy' in g:
            proxy = g['_LazyProxy'](mod_name)
            g[mod_name] = proxy
            return proxy
        # Fallback: create a tiny loader wrapper
        class _SimpleLazy:
            def __init__(self, name):
                self._name = name
                self._mod = None
            def _load(self):
                if self._mod is None:
                    self._mod = importlib.import_module(self._name)
                return self._mod
            def __getattr__(self, item):
                return getattr(self._load(), item)
            def __bool__(self):
                return True
        proxy = _SimpleLazy(mod_name)
        g[mod_name] = proxy
        return proxy
    except Exception:
        try:
            return _LazyProxy(mod_name)
        except Exception:
            return None

# Ensure common heavy modules are lazily imported (no early import cost)
for _mod in ('numpy','np','pygame','vlc','moviepy','fitz','Image','ImageTk','matplotlib','plt','sounddevice','soundfile','pyaudio'):
    try:
        if _mod not in globals() or globals().get(_mod) is None:
            globals()[_mod] = lazy_import(_mod if _mod not in ('np','plt') else (_mod if _mod in ('np','plt') else _mod))
    except Exception:
        pass
