# --- Logging setup ---
from logging.handlers import RotatingFileHandler
from logging import FileHandler

# Canonical log path used by the app and file-manager helpers
LOG_PATH = Path(__file__).with_suffix('.log') if '__file__' in globals() else Path('forzeos.log')

# Configure root logger with a rotating file handler. Guard against multiple
# handler additions when reloading modules in interactive sessions.
root_logger = logging.getLogger()
root_logger.setLevel(logging.DEBUG)

# Ensure basic debug logging is visible when no handlers are configured
try:
    if not root_logger.handlers:
        logging.basicConfig(level=logging.DEBUG)
except Exception:
    pass

# Small filter to prevent immediate duplicate messages from being written
class _DedupFilter(logging.Filter):
    def __init__(self, window_secs=1.0):
        super().__init__()
        self._last_msg = None
        self._last_time = 0.0
        self._window = float(window_secs)

    def filter(self, record):
        try:
            now = time.time()
            msg = (record.levelno, record.getMessage())
            if msg == self._last_msg and (now - self._last_time) < self._window:
                return False
            self._last_msg = msg
            self._last_time = now
        except Exception:
            pass
        return True

# Only add a handler if one that writes to our LOG_PATH isn't already present
handler_exists = False
for h in list(root_logger.handlers):
    try:
        if getattr(h, 'baseFilename', None) and Path(getattr(h, 'baseFilename')) == Path(LOG_PATH):
            handler_exists = True
            break
    except Exception:
        pass

if not handler_exists:
    try:
        # RAM OPTIMIZATION: use a lightweight FileHandler to avoid extra buffering
        # and large internal rotation buffers that can grow in memory-heavy workloads.
        fh = FileHandler(str(LOG_PATH), encoding='utf-8')
        fmt = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
        fh.setFormatter(fmt)
        fh.addFilter(_DedupFilter(window_secs=1.0))
        root_logger.addHandler(fh)
    except Exception:
        # Fall back to basicConfig if handler creation fails
        logging.basicConfig(filename=str(LOG_PATH), level=logging.DEBUG,
                            format='%(asctime)s - %(levelname)s - %(message)s')

logger = logging.getLogger(__name__)

# --- Embedded Enhanced Offline Assistant ---
try:
    ASSISTANT_MEMORY_PATH = str(Path(__file__).with_name('assistant_memory_large.json'))
except Exception:
    ASSISTANT_MEMORY_PATH = 'assistant_memory_large.json'


class EnhancedAssistantAI:
    """Embedded offline assistant: larger memory, non-repeating, varied replies.

    Behavior:
    - On first use, if memory file is missing or tiny, generate ~10k seed phrases
      by combining small topic/word lists (cheap and deterministic-ish).
    - Use compact hashed n-gram vectorization for similarity (no external libs).
    - Maintain per-session recent-responses to avoid repeats.
    - Provide reply(text) and execute_command(text) used by ForzeOS.
    """
    def __init__(self, memory_path: str = ASSISTANT_MEMORY_PATH, vector_dim: int = 256,
                 ngram: int = 3, session_size: int = 100):
        self.memory_path = memory_path
        self.vector_dim = int(vector_dim)
        self.ngram = int(ngram)
        self.session_size = int(session_size)

        self.memory = []  # list[str]
        self._mem_vectors = []
        # sessions: session_id -> {history: [(role,text),...], recent_responses: [canon,...], seed, summary}
        self.sessions = {}

        # Lightweight session persistence (keeps recent conversation state)
        try:
            self.session_persist_path = str(Path(self.memory_path).with_suffix('.sessions.json'))
        except Exception:
            self.session_persist_path = (self.memory_path or 'assistant_memory') + '.sessions.json'

        # Maximum stored messages per-session (keeps memory light)
        self.max_session_history = min(max(20, int(self.session_size) * 2), 400)
        # Session summary length (chars) to keep context without heavy compute
        self.session_summary_maxlen = 512
        # persistence throttle: save after this many remembered interactions
        self._session_dirty_counter = 0
        self._session_save_interval = 6

        # If memory missing or very small, generate a large seed file (best-effort)
        try:
            if (not os.path.exists(self.memory_path)) or os.path.getsize(self.memory_path) < 64:
                self._generate_large_memory(target=10000)
        except Exception:
            # swallow errors; still attempt to load whatever exists
            logger.exception("assistant: memory generation check failed")

        self._load_memory()

        # Load any persisted session snippets (best-effort); do not fail startup
        try:
            self._load_sessions()
        except Exception:
            logger.debug('assistant: no previous sessions loaded')

    def _generate_large_memory(self, target=10000):
        """Generate a diverse set of short phrases and persist them as JSON.

        This keeps repository light while satisfying the user's request to have
        a large offline memory. Generation is fast and deterministic enough
        for our purposes; it's intentionally inexpensive.
        """
        try:
            topics = [
                'hayat','müzik','film','oyun','programlama','python','sanat','teknoloji',
                'yemek','seyahat','doğa','spor','bilim','tarih','matematik','psikoloji',
                'dil','kültür','ekonomi','siyaset','fotoğraf','tasarım','kod','mimari',
                'veri','güvenlik','robotik','uzay','ekoloji','sağlık','medya','internet'
            ]
            words = [
                'güzel','hızlı','yavaş','ilginç','kolay','zor','eski','yeni','büyük','küçük',
                'renkli','sessiz','gürültülü','parlak','karanlık','tatlı','acı','bahar','yaz','kış',
                'sevgi','arkadaş','aile','iş','proje','öğrenme','deney','deneyim','öneri','fikir',
                'kod','algoritma','arayüz','tasarım','sunum','test','hata','çözüm','adım','özet'
            ]

            phrases = []
            r = random.Random(12345)
            # Combine topic + 2 words or short templates until we reach target
            while len(phrases) < int(target):
                t = r.choice(topics)
                w1 = r.choice(words)
                w2 = r.choice(words)
                if r.random() < 0.55:
                    phrases.append(f"{t} {w1} {w2}")
                elif r.random() < 0.80:
                    phrases.append(f"{w1} hakkında {t}")
                else:
                    phrases.append(f"{t}: {w1}, {w2}")
                # add occasional English variants for mixed-language matching
                if r.random() < 0.05:
                    phrases.append(f"{t} and {w1}")
                # Keep list bounded by popping earliest if overshoot
                if len(phrases) > int(target):
                    phrases = phrases[:int(target)]

            try:
                with open(self.memory_path, 'w', encoding='utf-8') as fh:
                    json.dump(phrases, fh, ensure_ascii=False)
                logger.info("assistant: generated memory file with %d entries: %s", len(phrases), self.memory_path)
            except Exception:
                logger.exception("assistant: failed to write generated memory file")
        except Exception:
            logger.exception("assistant: error while generating large memory")

    def _load_memory(self):
        try:
            if os.path.exists(self.memory_path):
                with open(self.memory_path, 'r', encoding='utf-8') as fh:
                    data = json.load(fh)
                    if isinstance(data, list):
                        self.memory = [str(x) for x in data if isinstance(x, (str, int, float))]
                    else:
                        self.memory = [str(data)]
            else:
                self.memory = ["Merhaba!","Nasılsın?","Yardım etmek istiyorum."]
        except Exception:
            logger.exception("assistant: failed to load memory")
            self.memory = ["Merhaba!"]

        # Build cached vectors
        self._mem_vectors = [self._vectorize(m) for m in self.memory]

    def _vectorize(self, text: str):
        v = [0.0] * self.vector_dim
        s = (text or '').lower()
        padded = ' ' + s + ' '
        L = len(padded)
        for i in range(L - self.ngram + 1):
            gram = padded[i:i + self.ngram]
            h = int(hashlib.sha1(gram.encode('utf-8')).hexdigest(), 16)
            idx = h % self.vector_dim
            v[idx] += 1.0
        # normalize
        norm = math.sqrt(sum(x * x for x in v))
        if norm > 0:
            v = [x / norm for x in v]
        return v

    def _dot(self, a, b):
        s = 0.0
        for i in range(min(len(a), len(b))):
            s += a[i] * b[i]
        return s

    def _find_similar(self, text: str, top_n: int = 8):
        qv = self._vectorize(text)
        scores = []
        for mtext, mv in zip(self.memory, self._mem_vectors):
            try:
                sc = self._dot(qv, mv)
                scores.append((mtext, sc))
            except Exception:
                continue
        scores.sort(key=lambda x: x[1], reverse=True)
        return scores[:top_n]

    # ----------------- Session persistence helpers (lightweight) -----------------
    def _load_sessions(self):
        try:
            if not self.session_persist_path:
                return
            if os.path.exists(self.session_persist_path):
                with open(self.session_persist_path, 'r', encoding='utf-8') as fh:
                    data = json.load(fh)
                    if isinstance(data, dict):
                        for sid, info in data.items():
                            try:
                                hist = info.get('history') if isinstance(info.get('history'), list) else []
                                recent = info.get('recent_responses') if isinstance(info.get('recent_responses'), list) else []
                                summary = info.get('summary') if isinstance(info.get('summary'), str) else ''
                                self.sessions.setdefault(sid, {})
                                self.sessions[sid]['history'] = [(r, str(t)) for r, t in hist][-self.max_session_history:]
                                self.sessions[sid]['recent_responses'] = recent[-self.session_size:]
                                self.sessions[sid]['seed'] = info.get('seed') or int(time.time())
                                self.sessions[sid]['summary'] = summary
                            except Exception:
                                continue
        except Exception:
            logger.exception('assistant: failed to load sessions')

    def _save_sessions(self, force=False):
        try:
            # only persist light-weight pieces to avoid large disk usage
            if not getattr(self, 'session_persist_path', None):
                return
            if self._session_dirty_counter < 0:
                self._session_dirty_counter = 0
            # build serializable snapshot
            out = {}
            for sid, info in list(self.sessions.items()):
                try:
                    hist = info.get('history', [])[-self.max_session_history:]
                    recent = info.get('recent_responses', [])[-self.session_size:]
                    summary = info.get('summary', '')
                    out[sid] = {'history': hist, 'recent_responses': recent, 'summary': summary, 'seed': info.get('seed', int(time.time()))}
                except Exception:
                    continue
            # write atomically
            tmp = self.session_persist_path + '.tmp'
            try:
                with open(tmp, 'w', encoding='utf-8') as fh:
                    json.dump(out, fh, ensure_ascii=False)
                try:
                    os.replace(tmp, self.session_persist_path)
                except Exception:
                    shutil.move(tmp, self.session_persist_path)
            except Exception:
                logger.exception('assistant: failed to write sessions')
            finally:
                self._session_dirty_counter = 0
        except Exception:
            logger.exception('assistant: _save_sessions outer failure')

    def remember_interaction(self, role: str, text: str, session_id: str = None):
        """Lightweightly remember an interaction (user/assistant) for session context.

        Keeps only a bounded history and updates a short summary string used
        when generating replies. Persists periodically to disk.
        """
        try:
            sid = session_id or '__default__'
            if sid not in self.sessions:
                self.sessions[sid] = {'history': [], 'recent_responses': [], 'seed': int(time.time()), 'summary': '', 'profile': {}}
            sess = self.sessions[sid]
            # ensure profile exists
            if 'profile' not in sess:
                sess['profile'] = {}
            # Append and prune
            try:
                sess['history'].append((role, str(text)))
                if len(sess['history']) > self.max_session_history:
                    sess['history'] = sess['history'][-self.max_session_history:]
            except Exception:
                pass

            # Try to detect simple profile-setting phrases (very lightweight)
            try:
                txt = (text or '').strip()
                # English patterns
                m = re.search(r"\bmy name is\s+([A-Za-zÀ-ÖØ-öø-ÿ'\-\s]{1,40})\b", txt, re.I)
                if not m:
                    m = re.search(r"\bi am\s+([A-Za-zÀ-ÖØ-öø-ÿ'\-\s]{1,40})\b", txt, re.I)
                # Turkish patterns
                if not m:
                    m = re.search(r"\bbenim ad[iı]\s+([A-Za-zÇÖŞİÜĞçöşıüğ'\-\s]{1,40})\b", txt, re.I)
                if not m:
                    m = re.search(r"\bad[iı]m\s+([A-Za-zÇÖŞİÜĞçöşıüğ'\-\s]{1,40})\b", txt, re.I)
                if m:
                    try:
                        name = m.group(1).strip()
                        if name:
                            # store as a pending name and require user confirmation
                            sess['profile']['pending_name'] = name
                            # clear any previous awaiting flag so reply() will ask
                            sess.pop('awaiting_confirmation_for', None)
                            # mark dirty so profile persistence will pick up after confirmation
                            self._session_dirty_counter = max(0, self._session_dirty_counter)
                            self._session_dirty_counter += 1
                    except Exception:
                        pass
            except Exception:
                pass

            # Update small summary (concatenate last few lines truncated)
            try:
                parts = []
                # include only last few rounds: user+assistant pairs
                rev = list(reversed(sess['history']))[:12]
                for r, t in reversed(rev):
                    parts.append(f"{r}:{t}")
                summary = ' | '.join(parts)
                if len(summary) > self.session_summary_maxlen:
                    summary = summary[-self.session_summary_maxlen:]
                sess['summary'] = summary
            except Exception:
                pass

            # Count dirty writes and persist on interval
            try:
                self._session_dirty_counter += 1
                if self._session_dirty_counter >= self._session_save_interval:
                    # non-blocking save on a background thread to avoid UI pause
                    try:
                        threading.Thread(target=self._save_sessions, daemon=True).start()
                    except Exception:
                        try:
                            self._save_sessions()
                        except Exception:
                            pass
            except Exception:
                pass
        except Exception:
            logger.exception('assistant.remember_interaction failed')

    def get_session_context(self, session_id: str = None, max_chars: int = 512) -> str:
        sid = session_id or '__default__'
        try:
            info = self.sessions.get(sid) or {}
            s = info.get('summary') or ''
            if s and len(s) > max_chars:
                return s[-max_chars:]
            return s
        except Exception:
            return ''

    def set_user_profile(self, session_id: str, key: str, value):
        """Set a small profile key for a session (lightweight, persisted periodically)."""
        try:
            sid = session_id or '__default__'
            if sid not in self.sessions:
                self.sessions[sid] = {'history': [], 'recent_responses': [], 'seed': int(time.time()), 'summary': '', 'profile': {}}
            sess = self.sessions[sid]
            if 'profile' not in sess:
                sess['profile'] = {}
            sess['profile'][str(key)] = value
            # mark dirty for periodic save
            try:
                self._session_dirty_counter += 1
                if self._session_dirty_counter >= self._session_save_interval:
                    threading.Thread(target=self._save_sessions, daemon=True).start()
            except Exception:
                pass
            return True
        except Exception:
            logger.exception('assistant.set_user_profile failed')
            return False

    def get_user_profile(self, session_id: str = None, key: str = None):
        try:
            sid = session_id or '__default__'
            info = self.sessions.get(sid) or {}
            prof = info.get('profile') or {}
            if key is None:
                return prof
            return prof.get(key)
        except Exception:
            return None

    def reply(self, text: str, session_id: str = None) -> str:
        sid = session_id or '__default__'
        if sid not in self.sessions:
            self.sessions[sid] = {'history': [], 'recent_responses': [], 'seed': int(time.time())}
        sess = self.sessions[sid]
        t = (text or '').strip()
        if not t:
            return "Bir şey yazdın mı?"

        # record user turn via the session-aware helper (also updates summary)
        try:
            self.remember_interaction('user', t, sid)
        except Exception:
            try:
                sess['history'].append(('user', t))
            except Exception:
                pass

        # ensure small profile exists
        sess.setdefault('profile', {})

        # Personal-question shortcuts: check if the user asks about themselves or wants assistant capabilities
        low = t.lower()
        profile = sess.setdefault('profile', {})

        # Confirmation handling for name: if we are awaiting a name confirmation, handle yes/no
        if sess.get('awaiting_confirmation_for') == 'name':
            candidate = profile.get('pending_name') or profile.get('name')
            # simple yes/no detection (Turkish/English)
            if re.match(r'^(evet|e|yes|y)\b', low, re.I):
                # confirm the pending name
                name_to_set = profile.pop('pending_name', None) or profile.get('name')
                if name_to_set:
                    profile['name'] = name_to_set
                sess.pop('awaiting_confirmation_for', None)
                resp = f"Tamam, {profile.get('name')}. Hatırlayacağım."
                try:
                    self.remember_interaction('assistant', resp, sid)
                except Exception:
                    sess['history'].append(('assistant', resp))
                return resp
            if re.match(r'^(hayır|hayir|h|no|n)\b', low, re.I):
                # reject pending name
                profile.pop('pending_name', None)
                sess.pop('awaiting_confirmation_for', None)
                resp = "Tamam, adını kaydetmiyorum. İstersen şimdi 'Benim adım ...' diye söyleyebilirsin."
                try:
                    self.remember_interaction('assistant', resp, sid)
                except Exception:
                    sess['history'].append(('assistant', resp))
                return resp
            # otherwise re-prompt
            resp = f"Sanırım adın {candidate} — doğru mu? (evet/hayır)"
            try:
                self.remember_interaction('assistant', resp, sid)
            except Exception:
                sess['history'].append(('assistant', resp))
            return resp

        # name queries (English / Turkish)
        if re.search(r"\b(what is my name|who am i)\b", low) or re.search(r"\b(ad[iı]m ne|ben kimim|benim ad[iı]m ne)\b", low):
            # if we have a confirmed name or a pending name, ask for confirmation rather than asserting
            if profile.get('name'):
                sess['awaiting_confirmation_for'] = 'name'
                resp = f"Sanırım adın {profile.get('name')} — doğru mu?"
                try:
                    self.remember_interaction('assistant', resp, sid)
                except Exception:
                    sess['history'].append(('assistant', resp))
                return resp
            if profile.get('pending_name'):
                sess['awaiting_confirmation_for'] = 'name'
                resp = f"Sanırım adın {profile.get('pending_name')} — doğru mu?"
                try:
                    self.remember_interaction('assistant', resp, sid)
                except Exception:
                    sess['history'].append(('assistant', resp))
                return resp
            resp = "Adını bilmiyorum — bana adını söyleyebilirsin. Örneğin: 'Benim adım Ahmet'."
            try:
                self.remember_interaction('assistant', resp, sid)
            except Exception:
                sess['history'].append(('assistant', resp))
            return resp
        # capability queries
        if re.search(r"\b(what can you do|neler yapabilirsin|ne yapabiliyorsun)\b", low):
            resp = "Ben bir yardımcıyım: dosya açabilir, müzik veya galeri açabilir, not alabilirim. Kısa ve net cevaplar veririm. Bana 'open gallery' veya 'open music' gibi yazabilirsin."
            try:
                self.remember_interaction('assistant', resp, sid)
            except Exception:
                sess['history'].append(('assistant', resp))
            return resp

        # helper: normalize/canonicalize for repetition checks
        def _canon(s: str) -> str:
            s2 = (s or '').lower().strip()
            s2 = re.sub(r'[^\wÇÖŞİÜĞçöşıüğ\s]', ' ', s2)
            s2 = re.sub(r'\s+', ' ', s2).strip()
            return s2

        # find similar memory items (wider pool), then sanitize and filter
        sims = self._find_similar(t, top_n=24)
        raw_candidates = []
        for mtext, score in sims:
            try:
                cleaned = (mtext or '').strip()
                # remove excessive punctuation and trailing markers
                cleaned = re.sub(r'^[\W_]+|[\W_]+$', '', cleaned)
                cleaned = re.sub(r'\s{2,}', ' ', cleaned)
                # drop very short fragments
                if len(cleaned) < 3:
                    continue
                # require a modest score threshold for relevance
                if score <= 0.02:
                    continue
                raw_candidates.append((cleaned, float(score)))
            except Exception:
                continue

        # if nothing good, try last-resort simple paraphrase of input
        if not raw_candidates:
            resp = f"Anladım: {t}. Bunu biraz daha açar mısın?"
            c = _canon(resp)
            sess['recent_responses'].append(c)
            if len(sess['recent_responses']) > self.session_size:
                sess['recent_responses'].pop(0)
            try:
                self.remember_interaction('assistant', resp, sid)
            except Exception:
                sess['history'].append(('assistant', resp))
            try:
                self.memory.append(t)
                self._mem_vectors.append(self._vectorize(t))
            except Exception:
                pass
            return resp

        # choose distinct top candidates
        raw_candidates.sort(key=lambda x: x[1], reverse=True)
        picks = [c for c,_ in raw_candidates[:6]]

        # richer template pool, using str.format for clarity
        templates = [
            "Anladım — {C0}. Daha fazlasını ister misin?",
            "{C0} hakkında birkaç fikir: {C1} ve {C2}. Hangisini denemek istersin?",
            "Tamam, {C0} ile başlayalım. Sonra {C1} de yapabiliriz.",
            "Bence {C0} iyi bir başlangıç. {C1} de bir seçenek.",
            "İlginç; {C0} ve {C1} arasında şöyle düşünebiliriz: ...",
            "{C0} üzerine odaklanabiliriz. Ayrıca {C1} yararlı olabilir.",
        ]

        # small synonym swaps to introduce variation (lightweight)
        SYN = {'iyi':'güzel', 'başlangıç':'ilk adım', 'fikir':'öneri', 'deneyim':'tecrübe'}

        def _paraphrase(s: str) -> str:
            if not s:
                return s
            out = s
            if random.random() < 0.35:
                for a,b in SYN.items():
                    out = re.sub(r'\b' + re.escape(a) + r'\b', b, out)
            return out

        # try composing responses avoiding recent canonical repeats
        tries = 0
        while tries < 8:
            tries += 1
            tpl = random.choice(templates)
            try:
                C0 = picks[0] if len(picks) > 0 else ''
                C1 = picks[1] if len(picks) > 1 else ''
                C2 = picks[2] if len(picks) > 2 else ''
                resp = tpl.format(C0=_paraphrase(C0), C1=_paraphrase(C1), C2=_paraphrase(C2))
            except Exception:
                resp = tpl

            # punctuation/spacing cleanup
            resp = re.sub(r'\s+([,\.:;\?\!])', r'\1', resp)
            resp = re.sub(r'[,;:\.]{2,}', lambda m: m.group(0)[0], resp)
            resp = resp.strip()

            canon = _canon(resp)
            # avoid near-duplicates using canonical form
            if canon in sess['recent_responses']:
                continue

            # record and return
            sess['recent_responses'].append(canon)
            if len(sess['recent_responses']) > self.session_size:
                sess['recent_responses'].pop(0)
            try:
                self.remember_interaction('assistant', resp, sid)
            except Exception:
                sess['history'].append(('assistant', resp))
            try:
                self.memory.append(t)
                self._mem_vectors.append(self._vectorize(t))
            except Exception:
                pass
            return resp

        # final fallback
        fallback = "Üzgünüm, şu an bunu net olarak cevaplayamıyorum; not aldım."
        fs = _canon(fallback)
        sess['recent_responses'].append(fs)
        if len(sess['recent_responses']) > self.session_size:
            sess['recent_responses'].pop(0)
        try:
            self.remember_interaction('assistant', fallback, sid)
        except Exception:
            sess['history'].append(('assistant', fallback))
        return fallback

    def execute_command(self, text: str, session_id: str = None):
        """Lightweight command detector that returns (handled_bool, message_or_action).
        ForzeOS can interpret True return as 'assistant handled and produced an action string'.
        """
        t = (text or '').lower()
        # simple heuristics
        if 'galeri' in t or 'gallery' in t or 'foto' in t:
            return True, 'open_gallery'
        if 'müzik' in t or 'music' in t:
            return True, 'open_music_studio'
        if 'dosya' in t or 'file' in t or 'explorer' in t:
            return True, 'open_file_manager'
        if 'terminal' in t or 'cmd' in t:
            return True, 'open_terminal'
        return False


# --- Security helpers (bcrypt if available) ---
try:
    import bcrypt
    BCRYPT_AVAILABLE = True
except Exception:
    BCRYPT_AVAILABLE = False

def hash_password(p: str) -> str:
    """Return a bcrypt hash if possible, otherwise md5 hex (legacy).

    New passwords will prefer bcrypt. Existing md5 hashes remain valid and
    will be transparently upgraded on successful login.
    """
    try:
        if BCRYPT_AVAILABLE:
            return bcrypt.hashpw(p.encode(), bcrypt.gensalt()).decode()
    except Exception:
        logger.exception("bcrypt hashing failed")
    # fallback (legacy): md5 hex
    return hashlib.md5(p.encode()).hexdigest()

def verify_password(p: str, h: str) -> bool:
    """Verify a password against stored hash `h`.

    Supports bcrypt hashes and legacy md5 hex.
    """
    try:
        if isinstance(h, str) and h.startswith('$2') and BCRYPT_AVAILABLE:
            return bcrypt.checkpw(p.encode(), h.encode())
        # legacy md5
        return hashlib.md5(p.encode()).hexdigest() == h
    except Exception:
        logger.exception("Password verify failed")
        return False

