def simple_ai_move(board_matrix):
    """Very small honest fallback AI: prefer captures then any adjacent move.

    Returns a tuple (from_row, from_col, to_row, to_col) or None.
    """
    try:
        # Prefer simple captures
        captures = []
        for r in range(8):
            for c in range(8):
                piece = board_matrix[r][c]
                if not piece:
                    continue
                for dr in (-1, 0, 1):
                    for dc in (-1, 0, 1):
                        if dr == 0 and dc == 0:
                            continue
                        rr, cc = r + dr, c + dc
                        if 0 <= rr < 8 and 0 <= cc < 8:
                            target = board_matrix[rr][cc]
                            if target and target.split('_')[0] != piece.split('_')[0]:
                                captures.append((r, c, rr, cc))
        if captures:
            return captures[0]

        # Otherwise return the first simple adjacent move found
        for r in range(8):
            for c in range(8):
                piece = board_matrix[r][c]
                if not piece:
                    continue
                for dr in (-1, 0, 1):
                    for dc in (-1, 0, 1):
                        if dr == 0 and dc == 0:
                            continue
                        rr, cc = r + dr, c + dc
                        if 0 <= rr < 8 and 0 <= cc < 8:
                            return (r, c, rr, cc)
    except Exception:
        pass
    return None

