    def register_window(self, window, name, icon=None, add_button=False):
        """Register a Toplevel/window with the OS window manager so taskbar
        and window-state helpers can track it.

        window: a tkinter Toplevel or widget
        name: string title to display in taskbar/task switcher
        icon: optional icon path or identifier
        """
        try:
            # store metadata keyed by object reference
            self.MANAGED_WINDOWS[window] = {'name': name, 'icon': icon, 'minimized': False, 'add_button': bool(add_button)}
            # If the provided `window` is a native wrapper (has hwnd) or
            # otherwise exposes a native handle, persist it so the taskbar
            # can focus external windows later.
            try:
                if hasattr(window, 'hwnd') and window.hwnd:
                    try:
                        self.MANAGED_WINDOWS[window]['hwnd'] = int(window.hwnd)
                    except Exception:
                        self.MANAGED_WINDOWS[window]['hwnd'] = window.hwnd
                # also accept raw integer hwnd passed as `window`
                elif isinstance(window, int) and window != 0:
                    self.MANAGED_WINDOWS[window]['hwnd'] = int(window)
            except Exception:
                pass
            # Optionally create a taskbar button now (default: do not)
            if add_button:
                try:
                    if hasattr(self, 'add_taskbar_button'):
                        # add_taskbar_button(title, window=None)
                        self.add_taskbar_button(name, window=window)
                except Exception:
                    # best-effort: ignore taskbar integration failures
                    logger.exception('register_window: taskbar integration failed')
            # If Task Manager is open, schedule apps tab refresh on the main thread
            try:
                if getattr(self, 'task_manager_window', None) and getattr(self, 'task_manager_window').winfo_exists() and hasattr(self, '_task_manager_refresh_apps'):
                    try:
                        self.task_manager_window.after(10, lambda: self._task_manager_refresh_apps())
                    except Exception:
                        pass
            except Exception:
                pass
            # If user enabled automatic window arranging, try to tile windows now
            try:
                if bool(self.config.get('settings', {}).get('auto_arrange_windows', False)):
                    try:
                        mode = self.config.get('settings', {}).get('window_arrange_mode', 'Tile Grid')
                        self.arrange_windows(mode=mode)
                    except Exception:
                        try:
                            self.arrange_windows_tile()
                        except Exception:
                            pass
            except Exception:
                pass
            # RAM OPTIMIZATION: ensure each managed window uses our safe destroy
            # so resources (images, threads, lists) are released when closed.
            try:
                if hasattr(window, 'protocol'):
                    try:
                        window.protocol("WM_DELETE_WINDOW", lambda w=window, n=name: self.destroy_window_fully(w, n))
                    except Exception:
                        pass
            except Exception:
                pass
        except Exception:
            logger.exception('register_window failed')

    def unregister_window(self, window):
        """Remove a window from management and taskbar."""
        try:
            info = self.MANAGED_WINDOWS.pop(window, None)
            if info and hasattr(self, 'remove_taskbar_button'):
                try:
                    self.remove_taskbar_button(info.get('name'))
                except Exception:
                    logger.exception('unregister_window: remove_taskbar_button failed')
            # If Task Manager is open, refresh apps tab
            try:
                if getattr(self, 'task_manager_window', None) and getattr(self, 'task_manager_window').winfo_exists() and hasattr(self, '_task_manager_refresh_apps'):
                    try:
                        self.task_manager_window.after(10, lambda: self._task_manager_refresh_apps())
                    except Exception:
                        pass
            except Exception:
                pass
        except Exception:
            logger.exception('unregister_window failed')

    # RAM OPTIMIZATION: centralized, safe window destruction and cleanup helper
    def destroy_window_fully(self, window, name=None):
        """Safely destroy a Toplevel/window and free associated resources.

        Actions:
        - stop/flag threads attached to window
        - destroy child widgets
        - clear PhotoImage/image refs attached to window
        - remove entries from MANAGED_WINDOWS and taskbar mappings
        - call gc.collect()
        """
        try:
            # Cancel any pending tkinter `after` callbacks registered for this window
            try:
                forzeos_cancel_all_for_widget(window)
            except Exception:
                pass
            # If this is the root window, perform global cleanup
            if getattr(self, 'root', None) is not None and window is getattr(self, 'root'):
                try:
                    self.cleanup_all_resources()
                except Exception:
                    pass

            # Stop any threads attached to this window
            try:
                threads = getattr(window, '_forze_threads', []) or []
                for t in list(threads):
                    try:
                        # signal stop via known attribute patterns
                        if hasattr(t, 'forze_stop'):
                            t.forze_stop.set() if hasattr(t.forze_stop, 'set') else setattr(t, 'forze_stop', True)
                        if hasattr(t, 'stop_requested'):
                            setattr(t, 'stop_requested', True)
                        # best-effort join short timeout
                        try:
                            t.join(0.05)
                        except Exception:
                            pass
                    except Exception:
                        pass
            except Exception:
                pass

            # Destroy and clear child widgets
            try:
                for child in list(window.winfo_children()):
                    try:
                        # attempt safe destroy helper if available
                        if hasattr(self, '_safe_destroy'):
                            try:
                                self._safe_destroy(child)
                            except Exception:
                                try:
                                    child.destroy()
                                except Exception:
                                    pass
                        else:
                            try:
                                child.destroy()
                            except Exception:
                                pass
                    except Exception:
                        pass
            except Exception:
                pass

            # RAM OPTIMIZATION: Clear image/photo refs attached to this window.
            # Use a simpler, flatter control flow to avoid deep nested try/except
            try:
                for attr in ('_image_refs', '_photoimage_refs', '_forze_image_refs'):
                    try:
                        if hasattr(window, attr):
                            val = getattr(window, attr)
                            if isinstance(val, (list, tuple, set)):
                                try:
                                    val.clear()
                                except Exception:
                                    pass
                            elif isinstance(val, dict):
                                try:
                                    val.clear()
                                except Exception:
                                    pass
                            # Remove attribute from window dict if present
                            try:
                                if hasattr(window, '__dict__') and attr in window.__dict__:
                                    try:
                                        del window.__dict__[attr]
                                    except Exception:
                                        try:
                                            setattr(window, attr, None)
                                        except Exception:
                                            pass
                            except Exception:
                                pass
                    except Exception:
                        # ignore issues per-attribute
                        pass
            except Exception:
                pass

            # Remove from MANAGED_WINDOWS by object or name
            try:
                try:
                    # pop by object key if present
                    self.MANAGED_WINDOWS.pop(window, None)
                except Exception:
                    # If stored by identity, iterate and remove references
                    for w, info in list(self.MANAGED_WINDOWS.items()):
                        try:
                            if info and (info.get('name') == name or w == window):
                                try:
                                    del self.MANAGED_WINDOWS[w]
                                except Exception:
                                    self.MANAGED_WINDOWS.pop(w, None)
                        except Exception:
                            pass
            except Exception:
                pass

            # Remove taskbar entries referencing this name
            try:
                if name and hasattr(self, 'remove_taskbar_button'):
                    try:
                        self.remove_taskbar_button(name)
                    except Exception:
                        pass
                # clean taskbar_icons and _tb_icon_refs
                try:
                    if hasattr(self, 'taskbar_icons'):
                        self.taskbar_icons.pop(name, None)
                except Exception:
                    pass
            except Exception:
                pass

            # Finally destroy the window widget itself
            try:
                if hasattr(window, 'destroy') and self._safe_winfo_exists(window):
                    try:
                        window.destroy()
                    except Exception:
                        try:
                            window.quit()
                        except Exception:
                            pass
            except Exception:
                pass

            # RAM OPTIMIZATION: force a garbage collection pass
            try:
                import gc
                gc.collect()
            except Exception:
                pass
        except Exception:
            logger.exception('destroy_window_fully failed for %s', getattr(window, 'title', lambda: name)())

    # RAM OPTIMIZATION: helper to start a daemon thread with a stop flag
    def _start_daemon_thread(self, target, args=(), kwargs=None, name=None):
        """Start a daemon thread and attach a `forze_stop` Event for cooperative stop.

        Returns the Thread object. Targets should check `getattr(threading.current_thread(), 'forze_stop', None)`.
        """
        try:
            import threading
            from threading import Event
            kwargs = kwargs or {}
            t = threading.Thread(target=target, args=args, kwargs=kwargs, name=name or None, daemon=True)
            # attach a stop Event the target can check
            try:
                t.forze_stop = Event()
            except Exception:
                try:
                    setattr(t, 'forze_stop', Event())
                except Exception:
                    pass
            try:
                t.start()
            except Exception:
                try:
                    # best-effort: try starting without extra metadata
                    threading.Thread(target=target, args=args, kwargs=kwargs, daemon=True).start()
                except Exception:
                    pass
            return t
        except Exception:
            return None

    # RAM OPTIMIZATION: clear global resource trackers (taskbar, icons, managed windows)
    def cleanup_all_resources(self):
        try:
            try:
                if hasattr(self, 'MANAGED_WINDOWS'):
                    # best-effort: clear mapping while avoiding reassigning type
                    for k in list(getattr(self, 'MANAGED_WINDOWS', {}).keys()):
                        try:
                            self.MANAGED_WINDOWS.pop(k, None)
                        except Exception:
                            pass
            except Exception:
                pass
            try:
                if hasattr(self, 'taskbar_icons'):
                    for k in list(self.taskbar_icons.keys()):
                        try:
                            self.taskbar_icons.pop(k, None)
                        except Exception:
                            pass
            except Exception:
                pass
            try:
                if hasattr(self, '_tb_icon_refs'):
                    try:
                        self._tb_icon_refs.clear()
                    except Exception:
                        self._tb_icon_refs = []
            except Exception:
                pass
            try:
                if hasattr(self, '_start_menu_icon_refs'):
                    try:
                        self._start_menu_icon_refs.clear()
                    except Exception:
                        self._start_menu_icon_refs = []
            except Exception:
                pass
            try:
                import gc
                gc.collect()
            except Exception:
                pass
        except Exception:
            logger.exception('cleanup_all_resources failed')

    def minimize_window(self, window):
        """Minimize (iconify) a managed window and notify taskbar if present.

        Keep the taskbar button visible; avoid withdraw() which removes the
        taskbar entry. Fall back to withdraw only as a last resort if
        iconify/iconify-like calls fail on some platforms.
        """
        try:
            if window in self.MANAGED_WINDOWS:
                try:
                    window.iconify()
                except Exception as e:
                    print(e)
                # mark as minimized in our metadata
                try:
                    self.MANAGED_WINDOWS[window]['minimized'] = True
                except Exception as e:
                    print(e)
                # notify taskbar object if available
                try:
                    if hasattr(self, 'taskbar') and hasattr(self.taskbar, 'update_window_state'):
                        self.taskbar.update_window_state(window, 'minimized')
                except Exception as e:
                    print(e)
        except Exception as e:
            logger.exception('minimize_window failed: %s', e)

    def open_market(self):
        """Open the ForzeOS Market using the market module's helper.

        Delegates creation to forze_market.run_embedded(host=self) so the
        market module controls its own lifecycle. Keeps a reference in
        self._market_window when successful.
        """
        try:
            try:
                logger.debug("open_market: invoking embedded market via forze_market.run_embedded")
            except Exception:
                pass

            # Try import first
            forze_market = None
            try:
                import forze_market
                forze_market = forze_market
            except Exception:
                forze_market = None

            win = None
            if forze_market is not None:
                try:
                    win = forze_market.run_embedded(self)
                except Exception:
                    logger.exception('forze_market.run_embedded failed')
            else:
                # Fallback: spawn external script if specified in custom_apps
                try:
                    mp = (self.custom_apps or {}).get('ForzeOS Market')
                except Exception:
                    mp = None
                if mp and isinstance(mp, str) and os.path.exists(mp):
                    try:
                        subprocess.Popen([sys.executable, mp])
                    except Exception:
                        logger.exception('Failed to spawn external market script')
                # Attempt to import again (module may be on sys.path now)
                try:
                    import forze_market as _fm
                    try:
                        win = _fm.run_embedded(self)
                    except Exception:
                        logger.exception('forze_market.run_embedded (post-spawn) failed')
                except Exception:
                    pass

            # If a window was returned, keep a reference and register metadata
            if win:
                try:
                    self._market_window = win
                except Exception:
                    pass
                try:
                    # Register the market window metadata but schedule the taskbar button
                    # creation on the Tk main loop to avoid any potential threading/race issues.
                    self.register_window(self._market_window, 'ForzeOS Market', icon=getattr(self, 'custom_icons', {}).get('ForzeOS Market'), add_button=False)
                    try:
                        # Ensure GUI work happens on the main thread
                        if hasattr(self, 'root') and getattr(self, 'root') is not None:
                            self.root.after(0, lambda: self.add_taskbar_button('ForzeOS Market', window=getattr(self, '_market_window', None)))
                        else:
                            # fallback: immediate call
                            self.add_taskbar_button('ForzeOS Market', window=getattr(self, '_market_window', None))
                    except Exception:
                        logger.exception('add_taskbar_button (Market) scheduling failed')
                except Exception:
                    logger.exception('register_window for Market failed')
        except Exception:
            logger.exception('open_market unexpected error')

    def rebuild_taskbar(self):
        """Taskbar ayarı (boyut, tema, pozisyon) değiştiğinde yeniden oluştur."""
        try:
            # Taskbar’ı tamamen yeniden oluştur
            if hasattr(self, 'taskbar') and self.taskbar:
                self.taskbar.destroy()

            self.create_taskbar()  # kendi taskbar oluşturma fonksiyonun varsa

            # Açık pencereleri yeniden taskbara ekle
            for win, info in list(self.MANAGED_WINDOWS.items()):
                if info.get('add_button'):
                    name = info.get('name', 'App')
                    try:
                        self.add_taskbar_button(name, window=win)
                    except Exception as e:
                        logger.exception(f"Taskbar re-add failed for {name}: {e}")
        except Exception as e:
            logger.exception(f"rebuild_taskbar failed: {e}")
    
    def _restart_taskbar(self, delay_ms: int = 120):
        """Force a clean taskbar destroy/create cycle and re-add icons.

        This is a small helper to centralize the aggressive restart semantics
        triggered by taskbar setting changes. It attempts a safe destroy of
        existing widgets, clears any temporary icon references that might be
        tied to old widgets (helping avoid PhotoImage GC/resurrection bugs),
        then schedules create_taskbar after a short delay and re-registers
        managed windows that requested taskbar buttons.
        """
        try:
            # Best-effort destroy existing taskbar and children
            try:
                if hasattr(self, 'taskbar') and self.taskbar is not None:
                    try:
                        self.taskbar.destroy()
                    except Exception:
                        try:
                            self.taskbar.pack_forget()
                        except Exception:
                            pass
                    finally:
                        try:
                            del self.taskbar
                        except Exception:
                            pass
            except Exception:
                pass

            # Clear internal cached PhotoImage refs so old images don't linger
            try:
                if hasattr(self, '_tb_icon_refs'):
                    # Replace with a new list to drop references to old TK images
                    self._tb_icon_refs = []
            except Exception:
                pass

            # Schedule creation slightly later to let Tk fully release resources
            try:
                self.root.after(delay_ms, lambda: self.create_taskbar())
            except Exception:
                try:
                    # immediate fallback
                    self.create_taskbar()
                except Exception:
                    logger.exception("_restart_taskbar: failed to create taskbar")

            # Try to re-add managed windows after a short grace period
            def _readd():
                try:
                    for win, info in list(self.MANAGED_WINDOWS.items()):
                        try:
                            if not getattr(win, 'winfo_exists', lambda: False)():
                                continue
                            if info.get('add_button'):
                                self.add_taskbar_button(info.get('name', 'App'), window=win)
                        except Exception:
                            pass
                except Exception:
                    pass

            try:
                # run a touch later to ensure create_taskbar completed
                self.root.after(max(200, delay_ms + 80), _readd)
            except Exception:
                try:
                    _readd()
                except Exception:
                    pass
        except Exception:
            logger.exception("_restart_taskbar unexpected error")
            
    def open_social_media(self, url=None):
        """Gelişmiş sosyal medya tarayıcı (tkinterweb ile)"""
        if not BROWSER_AVAILABLE:
            messagebox.showerror("Hata", "tkinterweb kütüphanesi yüklü değil!")
            return

        # Eğer daha önce açılmışsa aynı pencereyi getir (saf null kontrolü)
        sw = getattr(self, 'social_window', None)
        if sw and getattr(sw, 'winfo_exists', lambda: False)():
            if url:
                try:
                    sb = getattr(self, 'social_browser', None)
                    if sb is not None:
                        sb.load_website(url)
                except Exception as e:
                    print(e)
            try:
                sw.lift()
            except Exception:
                pass
            return

        self.social_window = self.create_window("Sosyal Medya", 1000, 700)
        if not self.social_window:
            return

        # URL girişi ve butonlar için üst panel
        top_frame = tk.Frame(self.social_window, bg=self.colors['dark'])
        top_frame.pack(fill=tk.X)

        url_var = tk.StringVar(value=url if url else "https://")

        url_entry = tk.Entry(top_frame, textvariable=url_var, font=("Arial", 12), width=60)
        url_entry.pack(side=tk.LEFT, padx=5, pady=5, fill=tk.X, expand=True)

        def go_to_url():
            raw_url = url_var.get().strip()
            if not raw_url.startswith("http://") and not raw_url.startswith("https://"):
                raw_url = "https://" + raw_url
            try:
                self.social_browser.load_website(raw_url)
            except Exception as e:
                messagebox.showerror("Hata", f"Site yüklenemedi:\n{e}")

        go_btn = tk.Button(top_frame, text="Git", command=go_to_url, bg=self.colors['accent'], fg="white")
        go_btn.pack(side=tk.LEFT, padx=5)

        # Hızlı erişim butonları
        quick_sites = {
            "YouTube": "https://youtube.com",
            "Twitter": "https://twitter.com",
            "Instagram": "https://instagram.com",
            "Facebook": "https://facebook.com"
        }
        for name, link in quick_sites.items():
            tk.Button(top_frame, text=name, command=lambda l=link: url_var.set(l), 
                    bg=self.colors['light']).pack(side=tk.LEFT, padx=2)

        # Tarayıcı çerçevesi
        self.social_browser = HtmlFrame(self.social_window, horizontal_scrollbar="auto")
        self.social_browser.pack(fill=tk.BOTH, expand=True)

        # Varsayılan sayfa
        go_to_url()

        # Pencere kapanınca referansı sil
        def on_close():
            try:
                if hasattr(self, 'social_browser'):
                    self.social_browser.destroy()
                    self.social_browser = None
                if hasattr(self, 'social_window'):
                    self.social_window.destroy()
                    self.social_window = None
            except Exception as e:
                print(f"Social window close error: {e}")

        self.social_window.protocol("WM_DELETE_WINDOW", on_close)
