    def open_music_studio(self):
        """TempleOS tarzı gelişmiş Music Studio"""
        if not PYGAME_AVAILABLE:
            messagebox.showerror("Hata", "pygame yüklenmemiş!")
            return

        # If window already open bring to front
        if hasattr(self, 'music_window') and self.music_window.winfo_exists():
            self.music_window.lift()
            return

        import threading, time, json, wave, struct, random
        # Use global lazy 'np' proxy for numpy; initialize pygame mixer lazily
        try:
            if PYGAME_AVAILABLE and not getattr(self, '_forzeos_pygame_inited', False):
                try:
                    # prefer stereo and explicit sample rate
                    pygame.mixer.init(frequency=44100, size=-16, channels=2)
                    self._forzeos_pygame_inited = True
                except Exception:
                    try:
                        pygame.mixer.init()
                        self._forzeos_pygame_inited = True
                    except Exception:
                        self._forzeos_pygame_inited = False
        except Exception:
            self._forzeos_pygame_inited = getattr(self, '_forzeos_pygame_inited', False)

        # Create or reuse window
        self.music_window = self.create_window("🎶 Music Studio", 1100, 600)
        if not self.music_window:
            return

        # Ensure we clean up heavy resources when the window is closed
        def _music_on_close():
            try:
                self._music_stop = True
            except Exception:
                pass
            try:
                if getattr(self, '_forzeos_pygame_inited', False):
                    try:
                        pygame.mixer.stop()
                    except Exception:
                        pass
                    try:
                        pygame.mixer.quit()
                    except Exception:
                        pass
                    self._forzeos_pygame_inited = False
            except Exception:
                pass
            try:
                # drop heavy instance attributes
                for a in ('_music_copybuffer','_music_buf','_music_samples'):
                    try:
                        if hasattr(self, a):
                            delattr(self, a)
                    except Exception:
                        pass
            except Exception:
                pass
            try:
                gc.collect()
            except Exception:
                pass
            try:
                self.music_window.destroy()
            except Exception:
                pass

        try:
            self.music_window.protocol('WM_DELETE_WINDOW', _music_on_close)
        except Exception:
            pass

        # Configuration
        rows, cols = 16, 32
        sr = 44100

        # Tracks: each track has grid (rows x cols), instrument, volume, name
        if not hasattr(self, 'music_tracks'):
            self.music_tracks = []
        # initialize with two tracks if empty
        if not self.music_tracks:
            for tname in ("Melody", "Drums"):
                grid = [[0 for _ in range(cols)] for _ in range(rows)]
                self.music_tracks.append({'name': tname, 'grid': grid, 'instr': 'sine', 'vol': 0.9})

        # Keyboard recording state (persist across openings)
        if not hasattr(self, 'kb_recordings'):
            self.kb_recordings = []  # list of {note_index, time, dur, vel, instr}
        self.kb_recording = False
        self.kb_rec_start = 0.0

        # playback control
        self._music_stop = True
        self._music_loop = False
        self._music_copybuffer = None

        # UI layout
        rootf = tk.Frame(self.music_window, bg=self.colors['bg'])
        rootf.pack(fill=tk.BOTH, expand=True)

        control = tk.Frame(rootf, bg=self.colors['dark'])
        control.pack(fill=tk.X, padx=4, pady=4)

        bpm_var = tk.IntVar(value=120)
        tk.Label(control, text="Tempo (BPM):", bg=self.colors['dark'], fg="white").pack(side=tk.LEFT, padx=6)
        tk.Spinbox(control, from_=30, to=300, textvariable=bpm_var, width=5).pack(side=tk.LEFT)

        loop_var = tk.BooleanVar(value=False)
        tk.Checkbutton(control, text="Loop", variable=loop_var, bg=self.colors['dark'], fg='white').pack(side=tk.LEFT, padx=8)

        play_btn = tk.Button(control, text="▶ Play", bg=self.colors['accent'], fg='white')
        stop_btn = tk.Button(control, text="■ Stop", bg=self.colors['danger'], fg='white')
        play_btn.pack(side=tk.LEFT, padx=6)
        stop_btn.pack(side=tk.LEFT, padx=6)

        # Compact file controls (fits better in small windows)
        file_ctrl = tk.Frame(control, bg=self.colors['dark'])
        # shift slightly left from the right edge and raise a bit visually (moved a bit up/left)
        file_ctrl.pack(side=tk.RIGHT, padx=26, pady=0)

        file_backend_var = tk.StringVar(value='native')  # options: 'native' or 'internal'
        tk.Label(file_ctrl, text="File:", bg=self.colors['dark'], fg='white').pack(side=tk.LEFT)
        tk.OptionMenu(file_ctrl, file_backend_var, 'native', 'internal').pack(side=tk.LEFT, padx=(4,6))

        # Buttons for pattern IO (texts used by wiring code below)
        save_btn = tk.Button(file_ctrl, text='Save Pattern', bg=self.colors['success'], fg='white')
        load_btn = tk.Button(file_ctrl, text='Load Pattern', bg=self.colors['light'])
        export_btn = tk.Button(file_ctrl, text='Export WAV', bg=self.colors['light'])
        save_btn.pack(side=tk.LEFT, padx=2)
        load_btn.pack(side=tk.LEFT, padx=2)
        export_btn.pack(side=tk.LEFT, padx=2)

        # store backend selection on the instance so helper functions can read it
        self._music_file_backend_var = file_backend_var
        # expose bpm/loop/grid size so other apps (File Manager) can call programmatic save/load
        try:
            self._music_bpm_var = bpm_var
            self._music_loop_var = loop_var
            self._music_grid_size = (rows, cols)
        except Exception:
            pass

        # Left: track list
        left = tk.Frame(rootf, bg=self.colors['bg'])
        left.pack(side=tk.LEFT, fill=tk.Y, padx=4, pady=4)

        track_listbox = tk.Listbox(left, height=8)
        track_listbox.pack(fill=tk.X)
        for t in self.music_tracks:
            track_listbox.insert(tk.END, t['name'])

        def add_track():
            name = simpledialog.askstring('Track name', 'Enter track name:')
            if not name:
                return
            grid = [[0 for _ in range(cols)] for _ in range(rows)]
            self.music_tracks.append({'name': name, 'grid': grid, 'instr': 'sine', 'vol': 0.9})
            track_listbox.insert(tk.END, name)

        def remove_track():
            sel = track_listbox.curselection()
            if not sel:
                return
            idx = sel[0]
            # Protect default tracks (first two) from accidental deletion
            if idx < 2:
                messagebox.showinfo('Kaldırma engellendi', 'Varsayılan trackler kaldırılamaz.')
                return
            del self.music_tracks[idx]
            track_listbox.delete(idx)
            rebuild_grid()

        tk.Button(left, text="Add Track", command=add_track, bg=self.colors['accent'], fg='white').pack(fill=tk.X, pady=2)
        tk.Button(left, text="Remove Track", command=remove_track, bg=self.colors['danger'], fg='white').pack(fill=tk.X)

        # Middle: piano-roll canvas
        canvas_frame = tk.Frame(rootf, bg=self.colors['bg'])
        canvas_frame.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        grid_canvas = tk.Frame(canvas_frame, bg=self.colors['bg'])
        grid_canvas.pack(fill=tk.BOTH, expand=True)

        # store button widgets per track per row/col
        track_buttons = []

        def rebuild_grid():
            # clear
            for w in grid_canvas.winfo_children():
                w.destroy()
            track_buttons.clear()

            cols_local = cols
            for ti, track in enumerate(self.music_tracks):
                tb = []
                tk.Label(grid_canvas, text=track['name'], bg=self.colors['bg'], fg='white').grid(row=ti*rows, column=0)
                for r in range(rows):
                    row_widgets = []
                    for c in range(cols_local):
                        def make_cmd(ti, r, c):
                            return lambda: toggle_cell(ti, r, c)
                        b = tk.Button(grid_canvas, width=2, height=1, bg=self.colors['dark'], command=make_cmd(ti, r, c))
                        b.grid(row=ti*rows + r, column=c+1, padx=1, pady=1)
                        row_widgets.append(b)
                    tb.append(row_widgets)
                track_buttons.append(tb)
            refresh_buttons()

        def refresh_buttons():
            for ti, track in enumerate(self.music_tracks):
                for r in range(rows):
                    for c in range(cols):
                        val = track['grid'][r][c]
                        try:
                            widget = track_buttons[ti][r][c]
                            widget.config(bg='yellow' if val else self.colors['dark'])
                        except Exception:
                            pass

        def toggle_cell(ti, r, c):
            track = self.music_tracks[ti]
            track['grid'][r][c] = 1 - track['grid'][r][c]
            refresh_buttons()

        rebuild_grid()

        # Right: instruments and utilities
        right = tk.Frame(rootf, bg=self.colors['bg'])
        right.pack(side=tk.RIGHT, fill=tk.Y, padx=4, pady=4)

        tk.Label(right, text='Instruments', bg=self.colors['bg'], fg='white').pack()
        instr_var = tk.StringVar(value='sine')
        instr_menu = tk.OptionMenu(right, instr_var, 'sine', 'square', 'triangle', 'saw', 'noise')
        instr_menu.pack(fill=tk.X)

        tk.Label(right, text='Selected Track', bg=self.colors['bg'], fg='white').pack(pady=(8,0))
        sel_track_var = tk.IntVar(value=0)
        def on_select_track(evt):
            sel = track_listbox.curselection()
            if sel:
                sel_track_var.set(sel[0])
        track_listbox.bind('<<ListboxSelect>>', on_select_track)

        tk.Button(right, text='Copy Pattern', bg=self.colors['light'], command=lambda: copy_pattern()).pack(fill=tk.X, pady=2)
        tk.Button(right, text='Paste Pattern', bg=self.colors['light'], command=lambda: paste_pattern()).pack(fill=tk.X, pady=2)
        tk.Button(right, text='Random Pattern', bg=self.colors['light'], command=lambda: randomize_pattern()).pack(fill=tk.X, pady=2)

        # Add Keyboard button (opens dedicated keyboard window)
        def open_keyboard_window():
            win = tk.Toplevel(self.music_window)
            win.title('Music Studio - Keyboard')
            win.geometry('800x300')
            win.configure(bg=self.colors['bg'])

            # Controls (fixed duration/volume)
            ctrl = tk.Frame(win, bg=self.colors['dark'])
            ctrl.pack(fill=tk.X, pady=6)
            tk.Label(ctrl, text='Instrument:', bg=self.colors['dark'], fg='white').pack(side=tk.LEFT, padx=6)
            kb_instr = tk.StringVar(value='sine')
            tk.OptionMenu(ctrl, kb_instr, 'sine','square','triangle','saw','noise').pack(side=tk.LEFT)
            tk.Label(ctrl, text='Duration:', bg=self.colors['dark'], fg='white').pack(side=tk.LEFT, padx=12)
            dur_var = tk.DoubleVar(value=0.5)
            tk.Spinbox(ctrl, from_=0.05, to=5.0, increment=0.05, textvariable=dur_var, width=6).pack(side=tk.LEFT)
            tk.Label(ctrl, text='Vel:', bg=self.colors['dark'], fg='white').pack(side=tk.LEFT, padx=8)
            vel_var = tk.DoubleVar(value=1.0)
            tk.Scale(ctrl, from_=0.1, to=2.0, resolution=0.1, orient=tk.HORIZONTAL, variable=vel_var, length=120).pack(side=tk.LEFT)

            # Recording controls
            rec_btn_frame = tk.Frame(win, bg=self.colors['bg'])
            rec_btn_frame.pack(fill=tk.X, pady=4)
            rec_status = tk.Label(rec_btn_frame, text='Rec: Stopped', bg=self.colors['bg'], fg='white')
            rec_status.pack(side=tk.LEFT, padx=6)
            def start_rec():
                self.kb_recordings = []
                self.kb_recording = True
                self.kb_rec_start = time.time()
                rec_status.config(text='Rec: Recording')
            def stop_rec():
                self.kb_recording = False
                rec_status.config(text=f'Rec: Stopped ({len(self.kb_recordings)} events)')
            tk.Button(rec_btn_frame, text='Start Rec', command=start_rec, bg='green', fg='white').pack(side=tk.LEFT, padx=4)
            tk.Button(rec_btn_frame, text='Stop Rec', command=stop_rec, bg='red', fg='white').pack(side=tk.LEFT, padx=4)

            # Save/Load/Play recording
            def save_rec():
                if not self.kb_recordings:
                    messagebox.showinfo('Save', 'No recording to save.')
                    return
                p = filedialog.asksaveasfilename(defaultextension='.json', filetypes=[('JSON','*.json')])
                if not p:
                    return
                try:
                    with open(p, 'w', encoding='utf-8') as fh:
                        json.dump(self.kb_recordings, fh, ensure_ascii=False, indent=2)
                    messagebox.showinfo('Saved', f'Recording saved: {p}')
                except Exception as e:
                    messagebox.showerror('Error', str(e))

            def load_rec():
                p = filedialog.askopenfilename(filetypes=[('JSON','*.json')])
                if not p:
                    return
                try:
                    with open(p, 'r', encoding='utf-8') as fh:
                        data = json.load(fh)
                    # validate
                    if isinstance(data, list) and all(isinstance(x, dict) and 'note_index' in x for x in data):
                        self.kb_recordings = data
                        rec_status.config(text=f'Loaded {len(data)} events')
                        messagebox.showinfo('Loaded', 'Recording loaded.')
                    else:
                        raise ValueError('Invalid recording format')
                except Exception as e:
                    messagebox.showerror('Error', str(e))

            def play_rec():
                if not self.kb_recordings:
                    messagebox.showinfo('Play', 'No recording to play.')
                    return
                def runner():
                    start_t = time.time()
                    for ev in self.kb_recordings:
                        wait = ev.get('time', 0) - (time.time() - start_t)
                        if wait > 0:
                            time.sleep(wait)
                        try:
                            ni = ev.get('note_index', 0)
                            instr = ev.get('instr', 'sine')
                            dur = ev.get('dur', 0.5)
                            vel = ev.get('vel', 1.0)
                            play_key(ni, instr, dur=dur, vel=vel)
                        except Exception:
                            pass
                threading.Thread(target=runner, daemon=True).start()

            tk.Button(rec_btn_frame, text='Save Rec', command=save_rec).pack(side=tk.RIGHT, padx=4)
            tk.Button(rec_btn_frame, text='Load Rec', command=load_rec).pack(side=tk.RIGHT, padx=4)
            tk.Button(rec_btn_frame, text='Play Rec', command=play_rec).pack(side=tk.RIGHT, padx=4)

            # Mapping list
            mapping_frame = tk.Frame(win, bg=self.colors['bg'])
            mapping_frame.pack(fill=tk.BOTH, expand=True)
            tk.Label(mapping_frame, text='Key -> Note mapping (QWERTY):', bg=self.colors['bg'], fg='white').pack(anchor='nw')
            map_box = tk.Text(mapping_frame, height=4, bg=self.colors['light'])
            map_box.pack(fill=tk.X, padx=6, pady=4)
            keymap = list('qwertyuiopasdfgh')
            mapping_text = '\n'.join([f"{k} -> {int(261.63*(2**(i/12.0)))} Hz ({i})" for i,k in enumerate(keymap)])
            map_box.insert('1.0', mapping_text)
            map_box.config(state='disabled')

            # Virtual keyboard buttons
            vk_frame = tk.Frame(win, bg=self.colors['bg'])
            vk_frame.pack(fill=tk.X, pady=6)
            for i,k in enumerate(keymap):
                def make_press(k=k, i=i):
                    return lambda: play_key(i, kb_instr.get(), dur=dur_var.get(), vel=vel_var.get())
                b = tk.Button(vk_frame, text=k.upper(), width=4, command=make_press())
                b.pack(side=tk.LEFT, padx=2)

            # Allow keyboard mapping text to show simple summary
            map_summary = tk.Label(win, text='Tip: use virtual buttons or press QWERTY keys when window focused', bg=self.colors['bg'], fg='white')
            map_summary.pack(side=tk.BOTTOM, pady=4)

        def play_key(row_index, instr_name, dur=0.5, vel=1.0):
            # improved: accept duration and velocity, record if active
            f = 261.63*(2**(row_index/12.0))
            s = synth_wave_mono(f, dur, instr_name)
            # s is int16 mono array
            # apply velocity
            arrf = s.astype(np.float32)/32767.0 * float(vel)
            try:
                init = pygame.mixer.get_init()
                chans = init[2] if init and len(init) > 2 else 1
            except Exception:
                chans = 1
            if chans > 1:
                arr = np.tile(arrf.reshape(-1,1),(1,chans))
            else:
                arr = arrf
            try:
                make_sound_from_buffer(arr).play()
            except Exception as e:
                print('play_key error', e)
            # record event
            if getattr(self, 'kb_recording', False):
                try:
                    tnow = time.time() - self.kb_rec_start
                    self.kb_recordings.append({'note_index': row_index, 'time': tnow, 'dur': dur, 'vel': vel, 'instr': instr_name})
                except Exception:
                    pass

        tk.Button(right, text='Keyboard', bg=self.colors['accent'], fg='white', command=open_keyboard_window).pack(fill=tk.X, pady=6)

        from tkinter import colorchooser

        def change_grid_color():
            color = colorchooser.askcolor(title="Grid Rengini Seç")[1]
            if color:
                # Grid frame arka planını değiştir
                grid_canvas.config(bg=color)
                # Bütün hücre (button) arka planlarını da değiştir
                for tb in track_buttons:
                    for row in tb:
                        for btn in row:
                            if btn.cget("bg") == self.colors['dark']:  # sadece boş hücreler
                                btn.config(bg=color)

        # helpers for audio
        def make_sound_from_buffer(samples):
            try:
                init = pygame.mixer.get_init()
                chans = init[2] if init and len(init) > 2 else 1
            except Exception:
                chans = 1
            arr = np.asarray(samples)
            # If float array (-1..1) convert to int16
            if np.issubdtype(arr.dtype, np.floating):
                arr = np.clip(arr, -1.0, 1.0)
                arr = np.int16(arr * 32767)
            # Ensure shape for channels
            if chans > 1:
                if arr.ndim == 1:
                    arr = np.tile(arr.reshape(-1,1), (1, chans))
            return pygame.sndarray.make_sound(arr.copy())

        def synth_wave_mono(freq, dur, instr='sine'):
            # Higher-quality wave generation with a few harmonics and ADSR
            n = max(1, int(sr * dur))
            t = np.linspace(0, dur, n, endpoint=False)
            nyquist = sr / 2.0

            if instr == 'sine':
                # add subtle harmonics for warmth
                wave = np.sin(2*np.pi*freq*t) + 0.15*np.sin(2*np.pi*freq*2*t) + 0.07*np.sin(2*np.pi*freq*3*t)
            elif instr == 'square':
                wave = np.zeros_like(t)
                max_h = int(min(15, nyquist // freq))
                for k in range(1, max_h+1, 2):
                    wave += (1.0/k) * np.sin(2*np.pi*freq*k*t)
                wave *= (4/np.pi)
            elif instr == 'triangle':
                wave = np.zeros_like(t)
                max_h = int(min(11, nyquist // freq))
                for k in range(1, max_h+1, 2):
                    wave += ((-1)**((k-1)//2)) * (1.0/(k**2)) * np.sin(2*np.pi*freq*k*t)
                wave *= (8/np.pi**2)
            elif instr == 'saw':
                wave = np.zeros_like(t)
                max_h = int(min(15, nyquist // freq))
                for k in range(1, max_h+1):
                    wave += (1.0/k) * np.sin(2*np.pi*freq*k*t)
                wave *= (-2/np.pi)
            elif instr == 'noise':
                wave = np.random.uniform(-1.0, 1.0, size=n)
            else:
                wave = np.sin(2*np.pi*freq*t)

            # simple lowpass smoothing (moving average) to reduce aliasing on short buffers
            if len(wave) > 5:
                kernel = np.ones(3)/3.0
                wave = np.convolve(wave, kernel, mode='same')

            # ADSR envelope
            env = np.ones_like(wave)
            attack = int(min(0.01 * sr, n//10))
            decay = int(min(0.03 * sr, n//10))
            release = int(min(0.05 * sr, n//6))
            sustain_level = 0.8
            if attack > 0:
                env[:attack] = np.linspace(0.0, 1.0, attack)
            if decay > 0:
                dec_end = min(n, attack + decay)
                env[attack:dec_end] = np.linspace(1.0, sustain_level, dec_end - attack)
            if release > 0:
                env[-release:] = np.linspace(sustain_level, 0.0, release)
            wave *= env * 0.9

            # normalize
            maxv = np.max(np.abs(wave))
            if maxv > 0:
                wave = wave / maxv * 0.9

            return np.int16(np.clip(wave * 32767, -32767, 32767))

        # playback thread
        def playback_thread():
            chan = pygame.mixer.Channel(1)
            bpm = max(20, min(400, bpm_var.get()))
            step_time = 60.0/bpm/4.0
            col = 0
            while not self._music_stop:
                loop = loop_var.get()
                # Take a snapshot of tracks/grid sizes so concurrent UI actions
                # (adding/removing tracks, rebuilding grid) won't cause index errors
                tracks_snapshot = list(self.music_tracks)
                num_tracks = len(tracks_snapshot)
                current_rows = rows
                current_cols = cols

                # mix all tracks for this column (defensively check bounds)
                buf = np.zeros(int(sr*step_time), dtype=np.float32)
                for ti, track in enumerate(tracks_snapshot):
                    instr = track.get('instr', 'sine')
                    vol = track.get('vol', 0.9)
                    # guard row/col accesses in case the grid shape changed
                    for r in range(current_rows):
                        try:
                            if r < len(track.get('grid', [])) and current_cols > 0 and col < len(track['grid'][r]) and track['grid'][r][col]:
                                f = (261.63)*(2**(r/12.0))
                                n = synth_wave_mono(f, step_time, instr)
                                buf[:len(n)] += (n.astype(np.float32)/32767.0) * vol
                        except Exception:
                            # best-effort: skip malformed rows/cells
                            continue

                # normalize
                if np.any(buf):
                    m = np.max(np.abs(buf))
                    if m > 0:
                        buf = buf / m * 0.9
                    samples = np.int16(np.clip(buf*32767, -32767, 32767))
                    try:
                        init = pygame.mixer.get_init()
                        chans = init[2] if init and len(init) > 2 else 1
                    except Exception:
                        chans = 1
                    if chans <= 1:
                        arr = samples
                    else:
                        arr = np.tile(samples.reshape(-1,1),(1,chans))
                    try:
                        s = make_sound_from_buffer(arr)
                        chan.play(s)
                    except Exception as e:
                        print('Playback error', e)
                    finally:
                        # explicitly release large buffers to help GC
                        try:
                            del arr
                        except Exception:
                            pass
                        try:
                            del samples
                        except Exception:
                            pass
                        try:
                            del buf
                        except Exception:
                            pass
                        try:
                            del s
                        except Exception:
                            pass

                # UI highlight: compute the on/off value now and pass it into the
                # scheduled callback so the lambda does not re-index potentially
                # mutated structures later (avoids IndexError).
                for ti in range(num_tracks):
                    for r in range(current_rows):
                        try:
                            # safe widget lookup
                            try:
                                widget = track_buttons[ti][r][col]
                            except Exception:
                                continue

                            # determine if the cell is active using the snapshot
                            is_on = False
                            try:
                                if ti < num_tracks and r < len(tracks_snapshot[ti].get('grid', [])) and col < len(tracks_snapshot[ti]['grid'][r]):
                                    is_on = bool(tracks_snapshot[ti]['grid'][r][col])
                            except Exception:
                                is_on = False

                            # schedule UI update on main thread using the captured is_on
                            try:
                                if getattr(self, 'music_window', None) and getattr(self, 'music_window', 'w'):
                                    self.music_window.after(0, lambda w=widget, on=is_on: w.config(bg='red' if on else '#555'))
                                else:
                                    self.root.after(0, lambda w=widget, on=is_on: w.config(bg='red' if on else '#555'))
                            except Exception:
                                # best-effort: log and continue
                                logger.exception("Failed to schedule music UI highlight")
                        except Exception:
                            # avoid noisy stacktraces for transient UI races
                            continue

                time.sleep(step_time)

                # reset colors: same defensive approach as highlighting above
                for ti in range(num_tracks):
                    for r in range(current_rows):
                        try:
                            try:
                                widget = track_buttons[ti][r][col]
                            except Exception:
                                continue

                            is_on = False
                            try:
                                if ti < num_tracks and r < len(tracks_snapshot[ti].get('grid', [])) and col < len(tracks_snapshot[ti]['grid'][r]):
                                    is_on = bool(tracks_snapshot[ti]['grid'][r][col])
                            except Exception:
                                is_on = False

                            try:
                                # Schedule a safe config call that first verifies the widget still exists.
                                def _schedule_safe_config(parent, w, on_flag):
                                    def _inner():
                                        try:
                                            if getattr(w, 'winfo_exists', None) and w.winfo_exists():
                                                w.config(bg='yellow' if on_flag else self.colors.get('dark', '#000000'))
                                        except Exception:
                                            # Widget may have been destroyed between scheduling and execution
                                            return
                                    try:
                                        parent.after(0, _inner)
                                    except Exception:
                                        # Parent (window) might be destroyed; ignore
                                        return

                                parent = self.music_window if getattr(self, 'music_window', None) else self.root
                                _schedule_safe_config(parent, widget, is_on)
                            except Exception:
                                logger.exception("Failed to schedule music UI reset")
                        except Exception:
                            # suppress transient UI race errors
                            continue

                col += 1
                if col >= cols:
                    if loop:
                        col = 0
                    else:
                        break
            self._music_stop = True

        def start_playback():
            if not self._music_stop:
                return
            self._music_stop = False
            threading.Thread(target=playback_thread, daemon=True).start()

        def stop_playback():
            self._music_stop = True

        play_btn.config(command=start_playback)
        stop_btn.config(command=stop_playback)

        # Save / Load / Export / Copy-Paste / Random
        def save_pattern():
            # Background save to avoid UI freeze. Honors selected file dialog backend.
            def _do_save(path):
                try:
                    data = {'bpm': bpm_var.get(), 'loop': bool(loop_var.get()), 'cols': cols, 'rows': rows, 'tracks': []}
                    for t in self.music_tracks:
                        data['tracks'].append({'name': t['name'], 'instr': t.get('instr','sine'), 'vol': t.get('vol',0.9), 'grid': t['grid']})
                    with open(path, 'w', encoding='utf-8') as f:
                        json.dump(data, f, ensure_ascii=False, indent=2)
                except Exception as e:
                    try:
                        messagebox.showerror('Save error', str(e), parent=self.music_window)
                    except Exception:
                        pass

            backend = getattr(self, '_music_file_backend_var', None)
            backend = backend.get() if backend else 'native'
            if backend == 'native':
                path = filedialog.asksaveasfilename(defaultextension='.json', filetypes=[('JSON','*.json')], parent=self.music_window)
                if not path:
                    return
                threading.Thread(target=_do_save, args=(path,), daemon=True).start()
            else:
                # use internal chooser
                path = internal_choose_file(save=True, def_ext='.json', filetypes=[('JSON','*.json')])
                if not path:
                    return
                threading.Thread(target=_do_save, args=(path,), daemon=True).start()

        def load_pattern():
            # Background load and UI update on main thread
            def _do_load(path):
                try:
                    with open(path, 'r', encoding='utf-8') as f:
                        data = json.load(f)
                    def _apply():
                        try:
                            bpm_var.set(data.get('bpm', bpm_var.get()))
                            loop_var.set(bool(data.get('loop', False)))
                            tracks = data.get('tracks', [])
                            self.music_tracks.clear()
                            for t in tracks:
                                self.music_tracks.append({'name': t.get('name','Track'), 'instr': t.get('instr','sine'), 'vol': t.get('vol',0.9), 'grid': t.get('grid', [[0]*cols for _ in range(rows)])})
                            # rebuild UI
                            track_listbox.delete(0, tk.END)
                            for t in self.music_tracks:
                                track_listbox.insert(tk.END, t['name'])
                            rebuild_grid()
                        except Exception as e:
                            messagebox.showerror('Load error', f'Hata: {e}\nSeçilen dosya uyumsuz veya bozuk olabilir.', parent=self.music_window)
                    try:
                        if hasattr(self, 'music_window') and self.music_window and self.music_window.winfo_exists():
                            self.music_window.after(0, _apply)
                    except Exception:
                        _apply()
                except Exception as e:
                    try:
                        messagebox.showerror('Load error', str(e), parent=self.music_window)
                    except Exception:
                        pass

            backend = getattr(self, '_music_file_backend_var', None)
            backend = backend.get() if backend else 'native'
            if backend == 'native':
                path = filedialog.askopenfilename(filetypes=[('JSON','*.json')], parent=self.music_window)
                if not path:
                    return
                threading.Thread(target=_do_load, args=(path,), daemon=True).start()
            else:
                path = internal_choose_file(open=True, filetypes=[('JSON','*.json')])
                if not path:
                    return
                threading.Thread(target=_do_load, args=(path,), daemon=True).start()

        def export_wav():
            # Background render/export to avoid UI blocking
            def _do_export(path):
                try:
                    bpm = max(20, min(400, bpm_var.get()))
                    step_time = 60.0/bpm/4.0
                    total_samples = int(sr * step_time * cols)
                    mix = np.zeros(total_samples, dtype=np.float32)
                    for c in range(cols):
                        base_idx = int(c * step_time * sr)
                        for ti, track in enumerate(self.music_tracks):
                            instr = track.get('instr','sine')
                            vol = track.get('vol',0.9)
                            for r in range(rows):
                                if track['grid'][r][c]:
                                    f = (261.63)*(2**(r/12.0))
                                    s = synth_wave_mono(f, step_time, instr).astype(np.float32)/32767.0
                                    L = len(s)
                                    if base_idx + L > len(mix):
                                        mix = np.pad(mix, (0, base_idx + L - len(mix)))
                                    mix[base_idx:base_idx+L] += s * vol
                    # normalize
                    m = np.max(np.abs(mix))
                    if m>0:
                        mix = mix / m * 0.9
                    samples = np.int16(np.clip(mix*32767, -32767, 32767))
                    # write wav (mono)
                    with wave.open(path, 'wb') as wf:
                        wf.setnchannels(1)
                        wf.setsampwidth(2)
                        wf.setframerate(sr)
                        wf.writeframes(samples.tobytes())
                    try:
                        messagebox.showinfo('Export', f'WAV exported: {path}', parent=self.music_window)
                    except Exception:
                        pass
                except Exception as e:
                    try:
                        messagebox.showerror('Export error', str(e), parent=self.music_window)
                    except Exception:
                        pass

            backend = getattr(self, '_music_file_backend_var', None)
            backend = backend.get() if backend else 'native'
            if backend == 'native':
                path = filedialog.asksaveasfilename(defaultextension='.wav', filetypes=[('WAV','*.wav')], parent=self.music_window)
                if not path:
                    return
                threading.Thread(target=_do_export, args=(path,), daemon=True).start()
            else:
                path = internal_choose_file(save=True, def_ext='.wav', filetypes=[('WAV','*.wav')])
                if not path:
                    return
                threading.Thread(target=_do_export, args=(path,), daemon=True).start()

        # --- Internal lightweight modal file chooser ---
        def internal_choose_file(open=False, save=False, def_ext=None, filetypes=None):
            # returns absolute path or None. Simple explorer starting at cwd
            result = {'path': None}
            dlg = tk.Toplevel(self.music_window)
            try:
                logger.debug('internal_choose_file: transient call disabled for music chooser')
            except Exception:
                pass
            dlg.grab_set()
            dlg.title('Choose file' if open else 'Save file')
            dlg.geometry('560x360')

            # start internal chooser at app's file_system_root when available
            start_dir = getattr(self, 'file_system_root', None) or os.getcwd()
            if not os.path.exists(start_dir):
                try:
                    os.makedirs(start_dir)
                except Exception:
                    start_dir = os.getcwd()
            cwd = start_dir
            cur_dir = tk.StringVar(value=cwd)

            top = tk.Frame(dlg)
            top.pack(fill=tk.X, padx=6, pady=6)
            tk.Label(top, text='Directory:').pack(side=tk.LEFT)
            dir_entry = tk.Entry(top, textvariable=cur_dir, width=60)
            dir_entry.pack(side=tk.LEFT, padx=4)
            def refresh_list():
                try:
                    p = cur_dir.get()
                    files = os.listdir(p)
                    files.sort()
                    listbox.delete(0, tk.END)
                    # show dirs first
                    for fn in files:
                        listbox.insert(tk.END, fn)
                except Exception:
                    listbox.delete(0, tk.END)

            def go_up():
                p = os.path.dirname(cur_dir.get())
                cur_dir.set(p)
                refresh_list()

            tk.Button(top, text='Up', command=go_up).pack(side=tk.LEFT, padx=4)

            listbox = tk.Listbox(dlg)
            listbox.pack(fill=tk.BOTH, expand=True, padx=6, pady=6)

            def on_double(evt=None):
                sel = listbox.curselection()
                if not sel:
                    return
                name = listbox.get(sel[0])
                path = os.path.join(cur_dir.get(), name)
                if os.path.isdir(path):
                    cur_dir.set(path)
                    refresh_list()
                else:
                    result['path'] = path
                    dlg.destroy()

            listbox.bind('<Double-Button-1>', on_double)

            btn_frame = tk.Frame(dlg)
            btn_frame.pack(fill=tk.X, pady=6)
            def choose():
                sel = listbox.curselection()
                if sel:
                    name = listbox.get(sel[0])
                    path = os.path.join(cur_dir.get(), name)
                    if save and os.path.isdir(path):
                        messagebox.showwarning('Choose file', 'Please select a filename, not a folder.', parent=dlg)
                        return
                    result['path'] = path
                else:
                    # use entry value
                    val = simpledialog.askstring('Filename', 'Enter filename:', parent=dlg)
                    if not val:
                        return
                    path = os.path.join(cur_dir.get(), val)
                    if def_ext and not path.lower().endswith(def_ext):
                        path += def_ext
                    result['path'] = path
                dlg.destroy()

            tk.Button(btn_frame, text='Choose', command=choose).pack(side=tk.RIGHT, padx=6)
            tk.Button(btn_frame, text='Cancel', command=dlg.destroy).pack(side=tk.RIGHT)

            refresh_list()
            self.music_window.wait_window(dlg)
            return result['path']

        def copy_pattern():
            sel = track_listbox.curselection()
            if not sel:
                messagebox.showinfo('Copy', 'Select a track first')
                return
            ti = sel[0]
            self._music_copybuffer = json.dumps(self.music_tracks[ti]['grid'])

        def paste_pattern():
            sel = track_listbox.curselection()
            if not sel or not self._music_copybuffer:
                return
            ti = sel[0]
            try:
                grid = json.loads(self._music_copybuffer)
                self.music_tracks[ti]['grid'] = grid
                rebuild_grid()
            except Exception as e:
                messagebox.showerror('Paste error', str(e))

        def randomize_pattern():
            sel = track_listbox.curselection()
            ti = sel[0] if sel else 0
            grid = [[0 for _ in range(cols)] for _ in range(rows)]
            for c in range(cols):
                if random.random() < 0.35:
                    r = random.randrange(rows)
                    grid[r][c] = 1
            self.music_tracks[ti]['grid'] = grid
            rebuild_grid()

        # wire explicit Save/Load/Export buttons if present
        try:
            save_btn.config(command=save_pattern)
            load_btn.config(command=load_pattern)
            export_btn.config(command=export_wav)
        except Exception:
            # fallback: try to find by text
            control_children = control.winfo_children()
            for w in control_children:
                try:
                    if getattr(w, 'cget', None) and w.cget('text') == 'Save Pattern':
                        w.config(command=save_pattern)
                    if getattr(w, 'cget', None) and w.cget('text') == 'Load Pattern':
                        w.config(command=load_pattern)
                    if getattr(w, 'cget', None) and w.cget('text') == 'Export WAV':
                        w.config(command=export_wav)
                except Exception:
                    pass

        # wire right side utilities
        # copy/paste/random buttons are in right frame - find and bind
        for w in right.winfo_children():
            try:
                if getattr(w,'cget',None) and w.cget('text') == 'Copy Pattern':
                    w.config(command=copy_pattern)
                if getattr(w,'cget',None) and w.cget('text') == 'Paste Pattern':
                    w.config(command=paste_pattern)
                if getattr(w,'cget',None) and w.cget('text') == 'Random Pattern':
                    w.config(command=randomize_pattern)
            except Exception:
                pass

        # Keyboard mapping (qwerty -> 16 notes)
        keymap = list('qwertyuiopasdfgh')
        key_to_row = {k: i for i, k in enumerate(keymap)}

        def on_key(event):
            k = event.keysym.lower()
            if k in key_to_row:
                r = key_to_row[k]
                f = 261.63*(2**(r/12.0))
                s = synth_wave_mono(f, 0.5, instr_var.get())
                try:
                    init = pygame.mixer.get_init()
                    chans = init[2] if init and len(init) > 2 else 1
                except Exception:
                    chans = 1
                if chans > 1:
                    arr = np.tile(s.reshape(-1,1),(1,chans))
                else:
                    arr = s
                try:
                    make_sound_from_buffer(arr).play()
                except Exception as e:
                    print('Key play error', e)

        self.music_window.bind_all('<Key>', on_key)

        # initial selection
        if self.music_tracks:
            track_listbox.selection_set(0)
            sel_track_var.set(0)

        # expose helpers for unit tests or other code
        self.music_rebuild_grid = rebuild_grid
        self.music_refresh_buttons = refresh_buttons


    def open_video_player(self, filepath=None):
        """Gelişmiş VLC tabanlı video oynatıcı"""
        if not VLC_AVAILABLE:
            messagebox.showerror("Hata", "python-vlc kütüphanesi bulunamadı!")
            return

        # Tek pencere kontrolü
        if hasattr(self, 'video_window') and self.video_window.winfo_exists():
            self.video_window.lift()
            return

        self.video_window = self.create_window("Video Player", 900, 600)
        if not self.video_window:
            return

        # Eğer dosya seçilmediyse kullanıcıdan iste
        if not filepath:
            filepath = filedialog.askopenfilename(
                title="Video Aç",
                filetypes=[("Video Files", "*.mp4 *.avi *.mov *.mkv")]
            )
        if not filepath:
            self.video_window.destroy()
            return

        # VLC instance oluştur
        instance = vlc.Instance("--no-video-title-show")
        self.vlc_player = instance.media_player_new()
        media = instance.media_new(filepath)
        self.vlc_player.set_media(media)

        # Video panel
        video_panel = tk.Frame(self.video_window, bg="black")
        video_panel.pack(fill="both", expand=True)

        self.video_window.update_idletasks()
        if sys.platform.startswith("win"):
            self.vlc_player.set_hwnd(video_panel.winfo_id())
        elif sys.platform.startswith("linux"):
            self.vlc_player.set_xwindow(video_panel.winfo_id())
        elif sys.platform == "darwin":
            self.vlc_player.set_nsobject(video_panel.winfo_id())

        # Kontrol butonları
        controls = tk.Frame(self.video_window, bg=self.colors['dark'])
        controls.pack(fill=tk.X)

        tk.Button(controls, text="⏯ Oynat/Duraklat", command=lambda: self.vlc_player.pause(),
                bg=self.colors['accent'], fg="white").pack(side=tk.LEFT, padx=5, pady=5)

        tk.Button(controls, text="⏮ Geri 10sn", command=lambda: self.vlc_player.set_time(self.vlc_player.get_time() - 10000),
                bg=self.colors['light']).pack(side=tk.LEFT, padx=5, pady=5)

        tk.Button(controls, text="⏭ İleri 10sn", command=lambda: self.vlc_player.set_time(self.vlc_player.get_time() + 10000),
                bg=self.colors['light']).pack(side=tk.LEFT, padx=5, pady=5)

        tk.Button(controls, text="⏹ Durdur", command=lambda: self.vlc_player.stop(),
                bg=self.colors['danger'], fg="white").pack(side=tk.LEFT, padx=5, pady=5)

        # Ses kontrolü
        volume_var = tk.IntVar(value=self.vlc_player.audio_get_volume())
        volume_slider = tk.Scale(controls, from_=0, to=100, orient=tk.HORIZONTAL, variable=volume_var,
                                command=lambda v: self.vlc_player.audio_set_volume(int(v)))
        volume_slider.pack(side=tk.RIGHT, padx=10)

        # Pencere kapatma kontrolü
        def on_close():
            try:
                self.vlc_player.stop()
                self.vlc_player.release()
                del self.vlc_player
                del self.video_window
            except Exception as e:
                print(e)
            self.video_window.destroy()

        self.video_window.protocol("WM_DELETE_WINDOW", on_close)

        # Oynatmaya başla
        self.vlc_player.play()

    def open_video_editor(self):
        """FFmpeg tabanlı video editör - Sabit FFmpeg yolu ile"""
        # Warn if MoviePy is not available (some features depend on it)
        if not MOVIEPY_AVAILABLE:
            try:
                messagebox.showerror("Hata", "MoviePy kütüphanesi bulunamadı! Bazı düzenleme özellikleri devre dışı kalacaktır.")
            except Exception:
                pass
        import shutil
        import subprocess
        import threading
        import os
        from tkinter import filedialog, messagebox, BooleanVar, DoubleVar
        import tkinter as tk


        # yerine sabit yolu, önce config içinde ara sonra PATH'te ffmpeg arama:
        ffmpeg_path = self.config.get('settings', {}).get('ffmpeg_path') or shutil.which('ffmpeg')
        if not ffmpeg_path:
            messagebox.showerror("Hata", "FFmpeg bulunamadı. Lütfen ayarlardan ffmpeg_path belirtin veya ffmpeg'i PATH'e ekleyin.")
            return

        if hasattr(self, 'video_edit_window') and self.video_edit_window.winfo_exists():
            self.video_edit_window.lift()
            return

        self.video_edit_window = self.create_window("Video Editör", 500, 400)
        if not self.video_edit_window:
            return

        panel = tk.Frame(self.video_edit_window, bg=self.colors['bg'])
        panel.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        file_list = []

        # 📂 Video seçme
        def select_videos():
            files = filedialog.askopenfilenames(
                title="Video seç",
                filetypes=[("Video Files", "*.mp4 *.avi *.mov *.mkv")]
            )
            if files:
                file_list.clear()
                file_list.extend(files)
                files_label.config(text="\n".join([os.path.basename(f) for f in file_list]))

        tk.Button(panel, text="🎥 Videoları Seç", command=select_videos,
                bg=self.colors['accent'], fg="white").pack(pady=5)
        files_label = tk.Label(panel, text="Seçilen video yok", bg=self.colors['bg'], fg=self.colors['fg'])
        files_label.pack()

        # 🎯 Kırpma
        tk.Label(panel, text="Başlangıç (sn):", bg=self.colors['bg'], fg=self.colors['fg']).pack()
        start_var = DoubleVar(value=0)
        tk.Entry(panel, textvariable=start_var).pack()

        tk.Label(panel, text="Bitiş (sn, 0 = son):", bg=self.colors['bg'], fg=self.colors['fg']).pack()
        end_var = DoubleVar(value=0)
        tk.Entry(panel, textvariable=end_var).pack()

        # 🔇 Ses kontrol
        mute_var = BooleanVar(value=False)
        tk.Checkbutton(panel, text="Sesi kaldır", variable=mute_var,
                    bg=self.colors['bg'], fg=self.colors['fg']).pack()

        # 📌 İşlem durumu
        progress_label = tk.Label(panel, text="", bg=self.colors['bg'], fg="yellow")
        progress_label.pack(pady=5)

        # 💾 Videoyu kaydet
        def export_video():
            if not file_list:
                messagebox.showwarning("Uyarı", "Önce video seçmelisiniz!")
                return
            out_path = filedialog.asksaveasfilename(
                title="Düzenlenmiş videoyu kaydet",
                defaultextension=".mp4",
                filetypes=[("MP4 files", "*.mp4")]
            )
            if not out_path:
                return
            if not out_path.lower().endswith(".mp4"):
                out_path += ".mp4"

            def run_ffmpeg():
                try:
                    try:
                        progress_label.after(0, lambda: progress_label.config(text="🔄 Geçici dosyalar hazırlanıyor..."))
                    except Exception:
                        logger.exception("Failed to update progress_label (start)")

                    temp_files = []
                    for i, f in enumerate(file_list):
                        temp_out = f"temp_part_{i}.mp4"
                        temp_files.append(temp_out)

                        start_t = start_var.get()
                        end_t = end_var.get()
                        crop_args = []
                        if end_t > 0:
                            duration = end_t - start_t
                            crop_args = ["-ss", str(start_t), "-t", str(duration)]
                        elif start_t > 0:
                            crop_args = ["-ss", str(start_t)]

                        audio_args = ["-an"] if mute_var.get() else []

                        cmd = [ffmpeg_path, "-y", "-i", f] + crop_args + audio_args + \
                            ["-c:v", "libx264", "-c:a", "aac", temp_out]
                        subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)

                    try:
                        progress_label.after(0, lambda: progress_label.config(text="📑 Birleştirme listesi hazırlanıyor..."))
                    except Exception:
                        logger.exception("Failed to update progress_label (list)")
                    list_file = "temp_list.txt"
                    with open(list_file, "w", encoding="utf-8") as lf:
                        for tf in temp_files:
                            lf.write(f"file '{os.path.abspath(tf)}'\n")

                    try:
                        progress_label.after(0, lambda: progress_label.config(text="⏳ Videolar birleştiriliyor..."))
                    except Exception:
                        logger.exception("Failed to update progress_label (concat)")
                    concat_cmd = [ffmpeg_path, "-y", "-f", "concat", "-safe", "0", "-i", list_file,
                                "-c:v", "libx264", "-c:a", "aac", out_path]
                    subprocess.run(concat_cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)

                    try:
                        progress_label.after(0, lambda: progress_label.config(text="✅ İşlem tamamlandı!"))
                        progress_label.after(0, lambda: messagebox.showinfo("Tamam", f"Video kaydedildi:\n{out_path}"))
                    except Exception:
                        logger.exception("Failed to finalize ffmpeg export UI updates")

                    # Temizlik
                    for tf in temp_files:
                        if os.path.exists(tf):
                            os.remove(tf)
                    if os.path.exists(list_file):
                        os.remove(list_file)

                except Exception as e:
                    try:
                        progress_label.after(0, lambda: progress_label.config(text=f"❌ Hata: {e}"))
                    except Exception:
                        logger.exception("Failed to show ffmpeg error")

            threading.Thread(target=run_ffmpeg, daemon=True).start()

        tk.Button(panel, text="💾 Videoyu Kaydet", command=export_video,
                bg=self.colors['success'], fg="white").pack(pady=10)

    def __init__(self, safe_mode: bool = False, developer_mode: bool = False, quiet_start: bool = False):
        """Constructor.

        Args:
            safe_mode: when True, skip loading heavy applications/plugins at startup.
            developer_mode: enable extra debug features/logging (opt-in).
            quiet_start: suppress non-critical startup dialogs.
        """
        self.root = tk.Tk()
        self.root.title("FORZEOS - Advanced Desktop OS")

        # Prefer stereo output to avoid array depth mismatch with sndarray
        try:
            pygame.mixer.init(frequency=44100, size=-16, channels=2)
        except Exception:
            try:
                pygame.mixer.init(frequency=44100, size=-16)
            except Exception:
                pass

        self.system_sounds = {
            "startup": "sounds/startup.wav",
            "click": "sounds/click.wav",
            "shutdown": "sounds/shutdown.wav",
            "delete": "sounds/delete.wav"
        }

        # Install a safe callback-exception handler to avoid Tk background errors
        try:
            self.root.report_callback_exception = self._report_callback_exception
        except Exception:
            pass

        # Global Alt+F command/run palette and deferred desktop widgets
        try:
            if 'forzeos_core' in globals() and forzeos_core is not None:
                try:
                    # Alt+F opens small run/command palette
                    self.root.bind_all('<Alt-f>', lambda e: forzeos_core.show_command_palette(self))
                except Exception:
                    pass
                # Ensure the desktop-embedded weather widget is created after desktop initialization
                try:
                    if hasattr(forzeos_core, 'ensure_weather_widget'):
                        self.root.after(900, lambda: forzeos_core.ensure_weather_widget(self))
                except Exception:
                    logger.exception("Error scheduling ensure_weather_widget on startup")
        except Exception:
            pass

        # CLI-driven runtime flags
        self.safe_mode = bool(safe_mode)
        self.developer_mode = bool(developer_mode)
        self.quiet_start = bool(quiet_start)

        # Optimization diagnostics per AI directive
        try:
            memp = None
            try:
                if importlib.util.find_spec('psutil') is not None:
                    memp = float(psutil.virtual_memory().percent)
            except Exception:
                memp = None
            self.optimization_status = {
                "ram_ai_active": True,
                "last_cleanup": None,
                "last_memory_percent": memp,
                "actions_performed": []
            }
        except Exception:
            # ensure attribute exists even on failure
            try:
                self.optimization_status = {"ram_ai_active": False, "last_cleanup": None, "last_memory_percent": None, "actions_performed": []}
            except Exception:
                pass

        self._hidden_taskbar_windows = set()
        self.clock_timer = None  # Timer ID'sini saklamak için
        # Shutdown flag used by background loops/monitors to exit quickly
        self._shutting_down = False

        # Initialize notification system
        self.notifications = []
        self.notification_window = None
        self.unread_count = 0
        
        # Load monitoring state from config
        self.resource_monitoring = False  # Default is disabled for better startup performance
        if hasattr(self, 'config') and 'settings' in self.config:
            self.resource_monitoring = self.config['settings'].get('resource_monitoring', True)

        # Çoklu masaüstü sistemi
        self.current_desktop_index = 0
        self.desktops = [[]]  # masaüstü ikon listeleri
        self.desktop_windows = [[]]  # masaüstü pencereleri
        # In-memory trash store for deleted icons/files; persist via config
        self.trash = {}
        # Track removed icon names per-desktop so they don't reappear
        self.removed_icons = {}
        
        # Get screen dimensions
        self.screen_width = self.root.winfo_screenwidth()
        self.screen_height = self.root.winfo_screenheight()
        self.fullscreen_states = {}
        
        self.reset_castling_rights()

        # Detect orientation
        self.is_horizontal = self.screen_width > self.screen_height
        
        # Try fullscreen mode
        try:
            self.root.attributes('-fullscreen', True)
        except:
            self.root.geometry(f"{self.screen_width}x{self.screen_height}")
        
        # System variables
        self.current_user = None
        self.running_apps = {}
        # Maximum allowed concurrent ForzeOS-managed windows. 0 means unlimited.
        self.max_windows = 0
        self.windows = {}
        self.desktop_icons = []
        # Persistent taskbar icon metadata: title -> {btn, window, icon_img, icon_path, size}
        self.taskbar_icons = {}
        # Keep image refs for taskbar icons to avoid GC
        self._tb_icon_refs = getattr(self, '_tb_icon_refs', [])
        # Dynamic config path placed next to this script
        try:
            self.config_file = str(Path(__file__).with_name("forzeos_config.json"))
        except Exception:
            self.config_file = "forzeos_config.json"
        self.file_system_root = "forze_users"
        
        # System status variables
        self.wifi_enabled = True
        self.bluetooth_enabled = True
        self.battery_percentage = 100
        self.is_charging = False
        self.system_status_window = None
        
        # Desktop icon management
        self.dragging_icon = None
        # per-desktop icon positions: { "0": {"App Name": [x,y], ...}, "1": {...} }
        self.desktop_icon_positions = {}
        # legacy alias for code that may still reference icon_positions in unexpected places
        # prefer using the helper methods below: get_icon_positions / set_icon_position
        self.icon_positions = {}
        self.custom_icons = {}
        # Persistent collection of desktop-switch buttons (keeps metadata so
        # they can be recreated/reflowed when the taskbar is rebuilt)
        self.desktop_buttons = []
        
        # Performance optimization
        self.status_update_counter = 0
        self.last_cpu_check = 0
        self.last_ram_check = 0
        
        # Icon size system
        self.icon_size = 48  # Varsayılan ikon boyutu

        # Theme system
        self.current_theme = 'dark'
        self.themes = {
            'dark': {
                'bg': '#2C3E50',
                'fg': '#ECF0F1',
                'accent': '#3498DB',
                'success': '#27AE60',
                'warning': '#F39C12',
                'danger': '#E74C3C',
                'dark': '#34495E',
                'light': '#BDC3C7'
            },
            'light': {
                'bg': '#FFFFFF',
                'fg': '#2C3E50',
                'success': '#27AE60',
                'accent': '#3498DB',
                'warning': '#E67E22',
                'danger': '#C0392B',
                'dark': '#34495E',
                'light': '#95A5A6'
            }
        }
        
        # Color scheme
        self.colors = {
            'bg': '#2C3E50',
            'fg': '#ECF0F1',
            'accent': '#3498DB',
            'success': '#27AE60',
            'warning': '#F39C12',
            'danger': '#E74C3C',
            'dark': '#34495E',
            'light': '#BDC3C7'
        }
        
        # Initialize system
        self.init_file_system()
        self.load_config()
        # --- Forze Market integration (safe, best-effort) ---
        try:
            try:
                # Prefer explicit mapping in config desktop.custom_apps
                market_path = None
                if isinstance(self.config, dict):
                    market_path = self.config.get('desktop', {}).get('custom_apps', {}).get('ForzeOS Market')

                # Fallback: look next to the script forze_market.py
                if not market_path:
                    try:
                        candidate = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'forze_market.py')
                        if os.path.exists(candidate):
                            market_path = candidate
                    except Exception:
                        pass

                # Also check common Downloads location (user convenience)
                if not market_path:
                    try:
                        dl = os.path.join(os.path.expanduser('~'), 'Downloads', 'forze_market.py')
                        if os.path.exists(dl):
                            market_path = dl
                    except Exception:
                        pass

                if market_path and os.path.exists(market_path):
                    # register in runtime mapping used by many helpers
                    try:
                        if not hasattr(self, 'custom_apps') or not isinstance(self.custom_apps, dict):
                            self.custom_apps = {}
                        # At runtime prefer the host's callable `open_market` when available
                        # so clicks/open actions use the embedded function instead of
                        # launching an external script. Persisted config still stores the path.
                        self.custom_apps['ForzeOS Market'] = getattr(self, 'open_market', market_path) or market_path
                    except Exception:
                        pass

                    # Persist into config under desktop.custom_apps for future runs
                    try:
                        if 'desktop' not in self.config:
                            self.config['desktop'] = {}
                        if 'custom_apps' not in self.config['desktop'] or not isinstance(self.config['desktop'].get('custom_apps'), dict):
                            self.config['desktop']['custom_apps'] = {}
                        self.config['desktop']['custom_apps']['ForzeOS Market'] = market_path
                    except Exception:
                        pass

                    # Create a desktop icon (if not present) that opens the script
                    try:
                        # Determine a reasonable placement (use saved position when available)
                        px = 120; py = 120
                        try:
                            saved = self.get_icon_position('ForzeOS Market')
                            if saved and isinstance(saved, (list, tuple)) and len(saved) >= 2:
                                px, py = saved[0], saved[1]
                        except Exception:
                            pass
                        # create_desktop_icon will accept the path string and open it via open_script/run_script_embedded
                        try:
                            # Avoid creating duplicate canvas icons if one exists
                            if not getattr(self, 'canvas_icons_by_name', {}).get('ForzeOS Market'):
                                # Prefer opening Market in-process via host.open_market so it
                                # creates its own Toplevel and requests a taskbar button on map.
                                cmd = getattr(self, 'open_market', None) or market_path
                                self.create_desktop_icon('ForzeOS Market', cmd, px, py, width=getattr(self, 'icon_size', 48), height=getattr(self, 'icon_size', 48), icon_path=self.config.get('desktop', {}).get('custom_icons', {}).get('ForzeOS Market'))
                        except Exception:
                            pass
                    except Exception:
                        pass

                    # Add to pinned taskbar config (best-effort)
                    try:
                        if 'desktop' not in self.config:
                            self.config['desktop'] = {}
                        pinned = self.config['desktop'].get('pinned_taskbar')
                        if not isinstance(pinned, list):
                            pinned = []
                        if 'ForzeOS Market' not in pinned:
                            pinned.insert(0, 'ForzeOS Market')
                        self.config['desktop']['pinned_taskbar'] = pinned
                    except Exception:
                        pass

                    # Save updated config (best-effort)
                    try:
                        self.save_config()
                    except Exception:
                        pass
            except Exception:
                logger.exception('Forze Market integration failed during startup discovery')
        except Exception:
            # swallow all errors to avoid breaking startup
            pass
        # Load UI language early (will fall back to 'en')
        try:
            # preferred language stored under config['settings']['language']
            lang = self.config.get('settings', {}).get('language', 'en')
            try:
                self.load_language(lang)
            except Exception:
                # fallback to english
                try:
                    self.load_language('en')
                except Exception:
                    self.translations = {}
                    self.lang = 'en'
        except Exception:
            self.translations = {}
            self.lang = 'en'
            # log the failure; lang may or may not be defined depending on where the error occurred
            try:
                logger.exception("load_language failed during startup for lang=%s", lang)
            except Exception:
                logger.exception("load_language failed during startup")
        
        # --- Initialize assistant (modular-first, non-destructive) ---
        # Prefer the external modular assistant (`assistant_ai.AssistantAI`) when
        # available so the host exposes a single canonical assistant instance
        # (and `desktop_companion` / other modules can reuse it). If the modular
        # assistant isn't present or fails to initialize, fall back to the
        # embedded `EnhancedAssistantAI` implementation.
        try:
            # Force the modular `assistant_ai` to be ignored so we have a
            # deterministic single assistant implementation for the host.
            ModAssistant = None
            try:
                from hybrid_assistant import HybridAssistantAI
                try:
                    # Hybrid combines the rich session/profile behaviour with
                    # the lightweight pattern engine for jokes/snippets.
                    self.assistant = HybridAssistantAI()
                    logger.info("ForzeOS assistant initialized via HybridAssistantAI")
                except Exception:
                    logger.exception("HybridAssistantAI instantiation failed; falling back to embedded EnhancedAssistantAI")
                    try:
                        self.assistant = EnhancedAssistantAI(memory_path=ASSISTANT_MEMORY_PATH, session_size=80)
                        logger.info("ForzeOS assistant initialized using embedded EnhancedAssistantAI (fallback)")
                    except Exception:
                        logger.exception("Failed to create embedded EnhancedAssistantAI instance")
                        self.assistant = None
            except Exception:
                # If hybrid module missing/unavailable, fall back to embedded
                try:
                    self.assistant = EnhancedAssistantAI(memory_path=ASSISTANT_MEMORY_PATH, session_size=80)
                    logger.info("ForzeOS assistant initialized and attached to host (embedded)")
                except Exception:
                    logger.exception("Failed to create embedded EnhancedAssistantAI instance")
                    self.assistant = None
        except Exception:
            try:
                logger.exception("Assistant initialization check failed")
            except Exception:
                pass
        
        # Show login first
        self.root.withdraw()
        # cancel any existing periodic timers to avoid callbacks after widgets destroyed
        try:
            if hasattr(self, 'clock_timer') and self.clock_timer:
                try:
                    self.root.after_cancel(self.clock_timer)
                except Exception:
                    pass
        except Exception:
            pass
        # Show a custom loading screen once at startup, then proceed to login
        try:
            self.show_loading_screen()
        except Exception:
            # fallback to original behavior on any error
            try:
                self.show_login()
            except Exception:
                pass
        
        self.terminal_history = []  # Terminal komut geçmişi
        # ------------------ Idle auto-lock (security) ------------------
        try:
            # Read defaults from config (user may override via settings)
            sec_cfg = self.config.get('security', {}) if isinstance(self.config, dict) else {}
            self.auto_lock_enabled = bool(sec_cfg.get('auto_lock_enabled', True))
            # default 300 seconds (5 minutes)
            try:
                self.auto_lock_seconds = int(sec_cfg.get('auto_lock_seconds', 300))
            except Exception:
                self.auto_lock_seconds = 300

            # Track last user activity timestamp
            import time
            self.last_activity = time.time()
            self._idle_check_id = None

            # Bind global activity events to update last_activity. Throttle motion updates.
            try:
                self.root.bind_all('<Any-KeyPress>', lambda e: self._update_last_activity())
                self.root.bind_all('<Any-Button>', lambda e: self._update_last_activity())
                # Motion is very frequent; use small throttle inside handler
                self.root.bind_all('<Motion>', lambda e: self._on_motion_activity())
            except Exception:
                pass

            # Start periodic idle checker (runs on mainloop thread)
            try:
                # schedule first check after 10 seconds to avoid immediate locking at startup
                self._idle_check_id = self.root.after(10000, lambda: self._idle_check())
            except Exception:
                pass
        except Exception:
            # non-fatal: continue without auto-lock if any error occurs
            try:
                logger.exception("Failed to initialize idle auto-lock")
            except Exception:
                pass
        # Idle helper methods used by the bindings above. Kept compact and
        # conservative to avoid changing program flow or introducing threads.
        def _update_last_activity_stub():
            # placeholder in case methods called very early; real methods defined on self below
            try:
                self.last_activity = time.time()
            except Exception:
                pass

        # Attach concrete implementations to the instance so bound lambdas call them
        try:
            def _update_last_activity():
                """Update the last activity timestamp (keyboard / button events).

                Lightweight and safe; intended to be called from Tk event handlers
                on the main thread.
                """
                try:
                    import time as _time
                    self.last_activity = _time.time()
                except Exception:
                    pass

            def _on_motion_activity():
                """Throttled motion handler to avoid high-frequency updates.

                Only update the last_activity if a small debounce interval has
                passed since the previous motion event.
                """
                try:
                    import time as _time
                    now = _time.time()
                    lastm = getattr(self, '_last_motion_time', None)
                    # ignore frequent motions (throttle window ~0.7s)
                    if lastm and (now - lastm) < 0.7:
                        return
                    self._last_motion_time = now
                    self.last_activity = now
                except Exception:
                    pass

            def _idle_check():
                """Periodic idle checker scheduled via `root.after`.

                - If auto-lock is disabled or the system is shutting down, stop.
                - If idle timeout reached, invoke `lock_system` on the GUI thread.
                - Otherwise, reschedule another check.
                """
                try:
                    # respect feature flag
                    if not getattr(self, 'auto_lock_enabled', False):
                        return
                    import time as _time
                    now = _time.time()
                    last = getattr(self, 'last_activity', now)
                    # If the elapsed idle time exceeds threshold, request a lock
                    try:
                        if (now - last) >= int(getattr(self, 'auto_lock_seconds', 300)):
                            # Ensure lock runs on the Tk mainloop
                            try:
                                if getattr(self, 'root', None):
                                    try:
                                        self.root.after(0, self.lock_system)
                                    except Exception:
                                        # fallback direct call (best-effort)
                                        try:
                                            self.lock_system()
                                        except Exception:
                                            pass
                            except Exception:
                                try:
                                    logger.exception("_idle_check: failed to invoke lock_system")
                                except Exception:
                                    pass
                            return
                    except Exception:
                        # if any conversion/comparison fails, avoid locking and reschedule
                        pass

                    # If shutting down, do not reschedule
                    if getattr(self, '_shutting_down', False):
                        return

                    # Schedule next check; keep interval short for responsiveness but not CPU-heavy
                    interval = min(10, max(1, int(getattr(self, 'auto_lock_seconds', 300) / 6)))
                    try:
                        if getattr(self, 'root', None):
                            # store id so it can be cancelled elsewhere if needed
                            self._idle_check_id = self.root.after(interval * 1000, _idle_check)
                    except Exception:
                        pass
                except Exception:
                    try:
                        logger.exception("_idle_check failed")
                    except Exception:
                        pass

            # Assign to instance
            try:
                self._update_last_activity = _update_last_activity
                self._on_motion_activity = _on_motion_activity
                self._idle_check = _idle_check
            except Exception:
                # best-effort fallback
                try:
                    self._update_last_activity = _update_last_activity_stub
                except Exception:
                    pass
        except Exception:
            try:
                logger.exception("Failed to install idle helper methods")
            except Exception:
                pass

    def init_file_system(self):
        """Initialize the file system structure"""
        try:
            # Resolve file_system_root to an absolute path relative to the script file
            base_dir = os.path.dirname(os.path.abspath(__file__)) if '__file__' in globals() else os.getcwd()
            if not os.path.isabs(self.file_system_root):
                self.file_system_root = os.path.abspath(os.path.join(base_dir, self.file_system_root))
            os.makedirs(self.file_system_root, exist_ok=True)
        except Exception as e:
            # Fallback: ensure some directory exists to avoid crashes
            try:
                if not os.path.exists(self.file_system_root):
                    os.makedirs(self.file_system_root, exist_ok=True)
            except Exception:
                print(f"init_file_system error: {e}")
        
    def load_config(self):
        """Load system configuration"""
        try:
            if os.path.exists(self.config_file):
                with open(self.config_file, 'r', encoding='utf-8') as f:
                    self.config = json.load(f)

                # Desktop ayarlarını yükle
                if 'desktop' in self.config:
                    # load per-desktop positions if present
                    self.desktop_icon_positions = self.config['desktop'].get('desktop_icon_positions', {}) or {}
                    try:
                        self.icon_positions = self.desktop_icon_positions.get(str(self.current_desktop_index), {}) or {}
                    except Exception:
                        self.icon_positions = self.config['desktop'].get('icon_positions', {})
                    self.custom_icons = self.config['desktop'].get('custom_icons', {})
                    # Load custom apps (added by dragging .py to desktop)
                    self.custom_apps = self.config['desktop'].get('custom_apps', {})
                    # Per-desktop settings (d1, d2, ...)
                    self.desktop_settings = self.config['desktop'].get('desktop_settings', {})
                    
                    # Wallpaper ayarlarını al
                    wallpaper = self.config['desktop'].get('wallpaper', {})
                    if wallpaper.get('image') and os.path.exists(wallpaper['image']):
                        self.config['settings']['wallpaper_image'] = wallpaper['image']
                    else: 
                        self.config['settings']['wallpaper_color'] = wallpaper.get('color', '#2C3E50')
                # Load persisted icon_size if present (best-effort)
                try:
                    icon_sz = int(self.config.get('desktop', {}).get('icon_size', getattr(self, 'icon_size', 48)))
                    self.icon_size = icon_sz
                except Exception:
                    # keep existing/default icon_size on failure
                    pass

                # Ensure settings dict exists
                if 'settings' not in self.config or not isinstance(self.config['settings'], dict):
                    self.config['settings'] = {}

                # If older configs saved 'mouse' at top-level, migrate it into settings
                try:
                    if 'mouse' in self.config and 'mouse' not in self.config['settings']:
                        # move the top-level mouse dict under settings
                        self.config['settings']['mouse'] = self.config.pop('mouse') or {}
                except Exception:
                    # best-effort; ignore migration errors
                    pass

                # Ensure mouse settings exist and have sensible defaults
                try:
                    default_mouse = self.get_default_config().get('mouse', {})
                except Exception:
                    default_mouse = {}

                if 'mouse' not in self.config['settings'] or not isinstance(self.config['settings']['mouse'], dict):
                    self.config['settings']['mouse'] = default_mouse.copy() if isinstance(default_mouse, dict) else {}
                # Apply mouse settings immediately so UI behavior matches stored config
                try:
                    # apply_mouse_settings may rely on self.root; guard quietly
                    if hasattr(self, 'apply_mouse_settings'):
                        try:
                            self.apply_mouse_settings()
                        except Exception:
                            pass
                except Exception:
                    pass
            else:
                self.config = self.get_default_config()
                # Ensure custom_apps exists
                self.custom_apps = {}
                self.save_config()
                
        except Exception as e:
            print(f"Config load error: {e}")
            self.config = self.get_default_config()
            self.save_config()

    def load_language(self, lang_code: str):
        """Load translations from languages/<lang_code>.json into self.translations

        Falls back to 'en' if file missing. Keeps self.lang set to chosen code.
        """
        try:
            base = os.path.dirname(os.path.abspath(__file__)) if '__file__' in globals() else os.getcwd()
            lang_dir = os.path.join(base, 'languages')
            path = os.path.join(lang_dir, f"{lang_code}.json")
            if not os.path.exists(path):
                # fallback to english
                path = os.path.join(lang_dir, 'en.json')
                lang_code = 'en'
            with open(path, 'r', encoding='utf-8') as fh:
                self.translations = json.load(fh)
            self.lang = lang_code
            # Rebuild reverse lookup and apply translations to currently live UI
            try:
                self._build_reverse_translation_maps()
            except Exception:
                pass
            try:
                # apply translations to existing widgets immediately
                self.apply_translations_to_ui()
            except Exception:
                pass
        except Exception:
            self.translations = {}
            self.lang = lang_code if lang_code else 'en'

    def t(self, key: str, **kwargs) -> str:
        """Translate a key via loaded language dict. If not found, return key or formatted fallback."""
        try:
            val = self.translations.get(key, key)
            try:
                return val.format(**kwargs)
            except Exception:
                return val
        except Exception:
            return key

    def _build_reverse_translation_maps(self):
        """Build a map of visible strings -> translation key across available languages.

        This is best-effort: it allows runtime UI scanning to find widgets whose
        current visible text matches a translated value and map it to the
        corresponding translation key so we can replace it with another language.
        """
        try:
            base = os.path.dirname(os.path.abspath(__file__)) if '__file__' in globals() else os.getcwd()
            lang_dir = os.path.join(base, 'languages')
            reverse = {}
            # iterate language files and build value -> key map (last seen wins)
            if os.path.isdir(lang_dir):
                for fn in os.listdir(lang_dir):
                    if not fn.lower().endswith('.json'):
                        continue
                    code = os.path.splitext(fn)[0]
                    try:
                        with open(os.path.join(lang_dir, fn), 'r', encoding='utf-8') as fh:
                            data = json.load(fh)
                        for k, v in data.items():
                            try:
                                s = v.strip() if isinstance(v, str) else None
                            except Exception:
                                s = None
                            if s:
                                # store mapping from visible string to canonical key
                                reverse[s] = k
                    except Exception:
                        # skip problematic files
                        pass
            # Also include currently loaded translations so exact matches map
            try:
                for k, v in (self.translations or {}).items():
                    if isinstance(v, str):
                        reverse[v.strip()] = k
            except Exception:
                pass
            self._reverse_translation_map = reverse
        except Exception:
            self._reverse_translation_map = {}
            logger.exception("_build_reverse_translation_maps failed")

    def apply_translations_to_ui(self, root_widget=None):
        """Walk the widget tree starting at `root_widget` (or self.root) and update
        textual properties (text, title, menu labels) by mapping current visible
        strings to translation keys and applying `self.t(key)`.

        This is a best-effort approach and may not cover dynamically constructed
        strings or labels that include runtime variables. It avoids modifying
        widgets that don't match any known translation value.
        """
        try:
            if not hasattr(self, '_reverse_translation_map'):
                try:
                    self._build_reverse_translation_maps()
                except Exception:
                    pass

            mapping = getattr(self, '_reverse_translation_map', {}) or {}

            if root_widget is None:
                root_widget = getattr(self, 'root', None)
            if root_widget is None:
                return

            def try_update_widget(w):
                # Titles on Toplevels
                try:
                    if hasattr(w, 'winfo_toplevel') and callable(w.winfo_toplevel):
                        top = w.winfo_toplevel()
                        if top and getattr(top, 'title', None):
                            try:
                                cur = top.title()
                                if isinstance(cur, str) and cur.strip() in mapping:
                                    top.title(self.t(mapping[cur.strip()]))
                            except Exception:
                                pass
                except Exception:
                    pass

                # Generic widgets with 'text' option
                try:
                    if getattr(w, 'cget', None):
                        try:
                            cur = w.cget('text')
                            if isinstance(cur, str) and cur.strip():
                                key = mapping.get(cur.strip())
                                if key:
                                    try:
                                        w.config(text=self.t(key))
                                    except Exception:
                                        pass
                        except Exception:
                            pass
                except Exception:
                    pass

                # Menus: update entry labels where possible
                try:
                    if isinstance(w, tk.Menu):
                        try:
                            end = w.index('end')
                            if end is None:
                                return
                            for i in range(0, end+1):
                                try:
                                    label = w.entrycget(i, 'label')
                                    if label and label.strip() in mapping:
                                        w.entryconfig(i, label=self.t(mapping[label.strip()]))
                                except Exception:
                                    pass
                        except Exception:
                            pass
                except Exception:
                    pass

            # Recursive traversal
            def walk(parent):
                try:
                    try_update_widget(parent)
                except Exception:
                    pass
                try:
                    children = parent.winfo_children()
                except Exception:
                    children = []
                for ch in children:
                    walk(ch)

            walk(root_widget)
        except Exception:
            logger.exception("apply_translations_to_ui failed")

    def _call_cmd_safe(self, cmd, *args, **kwargs):
        """Invoke a command safely so UI click handlers return quickly.

        - If `cmd` is a bound method on this ForzeOS instance (likely a GUI-opener),
          schedule it on the Tk mainloop via `after` so it's executed on the GUI
          thread but not during the click event processing.
        - Otherwise invoke the callable in a daemon thread so blocking work
          (IO/subprocess) doesn't freeze the UI.
        """
        try:
            if callable(cmd):
                # Bound method check: has __self__ pointing to this instance
                try:
                    if getattr(cmd, '__self__', None) is self:
                        # Inspect the callable's signature to ensure we don't
                        # schedule a bound method that requires positional args
                        try:
                            import inspect
                            sig = inspect.signature(cmd)
                            params = list(sig.parameters.values())
                            # For bound methods inspect.signature returns the parameters
                            # excluding `self`, so any required positional params mean
                            # the method cannot be safely called without args.
                            required = [p for p in params if p.kind in (inspect.Parameter.POSITIONAL_ONLY, inspect.Parameter.POSITIONAL_OR_KEYWORD) and p.default is inspect._empty]
                            if len(required) > len(args):
                                # Prompt the user to select a file to pass to the
                                # command instead of failing silently.
                                def _prompt_and_call():
                                    try:
                                        name = getattr(cmd, '__name__', str(cmd))
                                        # Ask for a file; be permissive about types
                                        try:
                                            fp = filedialog.askopenfilename(title=f"Select file for {name}")
                                        except Exception:
                                            fp = None
                                        if not fp:
                                            try:
                                                # Inform user that command was cancelled
                                                messagebox.showinfo("Command cancelled", f"No file selected for {name}.")
                                            except Exception:
                                                pass
                                            return
                                        try:
                                            cmd(fp)
                                        except Exception:
                                            try:
                                                # try via safe dispatcher if direct call fails
                                                self._call_cmd_with_optional_filepath(cmd, fp)
                                            except Exception:
                                                logger.exception("Failed to invoke %s with selected file", name)
                                                try:
                                                    messagebox.showerror("Command error", f"Failed to run {name} with the selected file.")
                                                except Exception:
                                                    pass
                                    except Exception:
                                        pass

                                try:
                                    self.root.after(10, _prompt_and_call)
                                except Exception:
                                    try:
                                        _prompt_and_call()
                                    except Exception:
                                        pass
                                return True
                        except Exception:
                            # If inspection fails, fall back to safe scheduling below
                            pass

                        # Schedule on main thread shortly after the event returns
                        try:
                            self.root.after(10, lambda: cmd(*args, **kwargs))
                            return True
                        except Exception:
                            # fallback to direct call if scheduling fails
                            cmd(*args, **kwargs)
                            return True
                except Exception:
                    pass

                # For other callables, run in background thread
                try:
                    threading.Thread(target=lambda: cmd(*args, **kwargs), daemon=True).start()
                    return True
                except Exception:
                    # last resort: call directly
                    cmd(*args, **kwargs)
                    return True
        except Exception:
            logger.exception("_call_cmd_safe failed")
            return False

    def _call_cmd_with_optional_filepath(self, cmd, filepath=None):
        """Call a possibly-bound callable, passing `filepath` if the callable
        appears to accept a positional argument. Uses `_call_cmd_safe` for
        scheduling/execution.

        This avoids TypeError when a stored command is a bound method that
        requires a filepath parameter (e.g. self.open_file).
        """
        try:
            if not callable(cmd):
                return False
            try:
                import inspect
                sig = inspect.signature(cmd)
                params = list(sig.parameters.values())
                # If callable accepts *args or has at least one parameter,
                # it's safe to pass the filepath when provided.
                accepts_positional = any(
                    p.kind in (inspect.Parameter.POSITIONAL_ONLY, inspect.Parameter.POSITIONAL_OR_KEYWORD, inspect.Parameter.VAR_POSITIONAL)
                    for p in params
                )
            except Exception:
                accepts_positional = False

            if filepath and accepts_positional:
                return self._call_cmd_safe(cmd, filepath)
            else:
                return self._call_cmd_safe(cmd)
        except Exception:
            logger.exception("_call_cmd_with_optional_filepath failed")
            return False

