    def open_file_manager(self, path=None):
        """Open the file manager optionally at a given path. Stub for DesktopCompanion."""
        try:
            # If a dedicated file manager exists, call it; otherwise open explorer
            try:
                if path and os.path.exists(path):
                    # use platform open
                    if sys.platform.startswith('win'):
                        os.startfile(path)
                    else:
                        import subprocess
                        subprocess.Popen(['xdg-open', path])
                    return
            except Exception:
                pass
            # fallback: open root of file_system_root
            base = getattr(self, 'file_system_root', None) or os.getcwd()
            try:
                if sys.platform.startswith('win'):
                    os.startfile(base)
                else:
                    import subprocess
                    subprocess.Popen(['xdg-open', base])
            except Exception:
                pass

        except Exception:
            pass

    def open_log_file(self, path=None):
        """Open the canonical ForzeOS log file in the system default viewer.

        If a `path` is provided and exists, open that instead. On Windows uses
        os.startfile; on other platforms falls back to xdg-open / open.
        """
        try:
            target = None
            if path:
                try:
                    if os.path.exists(path):
                        target = path
                except Exception:
                    target = None
            if not target:
                try:
                    target = str(LOG_PATH)
                except Exception:
                    target = None
            if target and os.path.exists(target):
                try:
                    if sys.platform.startswith('win'):
                        os.startfile(target)
                        return
                    else:
                        import subprocess
                        opener = 'xdg-open' if sys.platform.startswith('linux') else 'open'
                        subprocess.Popen([opener, target])
                        return
                except Exception:
                    try:
                        messagebox.showinfo('Log file', f'Log: {target}')
                    except Exception:
                        pass
            else:
                try:
                    messagebox.showinfo('Log not found', f'Log path: {target} (file does not exist)')
                except Exception:
                    pass
        except Exception:
            pass

    def show_log_viewer(self, lines=400, poll_interval=1000):
        """Open a simple live-updating log viewer Toplevel showing the last
        `lines` lines and polling the log file every `poll_interval` ms.

        This is intentionally small and uses file reopen on each poll so it
        behaves reasonably across log rotation.
        """
        try:
            # If already open, raise to front
            info = getattr(self, '_log_viewer_info', None)
            if info and info.get('toplevel') and info['toplevel'].winfo_exists():
                try:
                    info['toplevel'].deiconify()
                    info['toplevel'].lift()
                except Exception:
                    pass
                return

            import tkinter as tk
            from tkinter import scrolledtext

            top = tk.Toplevel(self.root)
            top.title('ForzeOS - Log Viewer')
            top.geometry('900x420')

            frame = tk.Frame(top)
            frame.pack(fill=tk.BOTH, expand=True)

            txt = scrolledtext.ScrolledText(frame, wrap=tk.NONE, state='disabled')
            txt.pack(fill=tk.BOTH, expand=True)

            ctl_frame = tk.Frame(top)
            ctl_frame.pack(fill=tk.X)

            paused = tk.BooleanVar(value=False)

            def _toggle_pause():
                paused.set(not paused.get())

            tk.Button(ctl_frame, text='Pause/Resume', command=_toggle_pause).pack(side=tk.LEFT, padx=6)
            tk.Button(ctl_frame, text='Open in Editor', command=lambda: self.open_log_file()).pack(side=tk.LEFT, padx=6)
            tk.Button(ctl_frame, text='Close', command=lambda: (self._safe_destroy(top))).pack(side=tk.RIGHT, padx=6)

            # store viewer info
            self._log_viewer_info = {
                'toplevel': top,
                'text': txt,
                'lines': lines,
                'pos': 0,
                'paused': paused,
                'job': None
            }

            def _read_initial():
                try:
                    p = str(LOG_PATH)
                except Exception:
                    p = None
                if not p or not os.path.exists(p):
                    return
                try:
                    with open(p, 'r', encoding='utf-8', errors='ignore') as fh:
                        data = fh.read()
                        parts = data.splitlines(True)
                        last = ''.join(parts[-lines:]) if parts else ''
                        txt.configure(state='normal')
                        txt.delete('1.0', tk.END)
                        txt.insert(tk.END, last)
                        txt.configure(state='disabled')
                        # move to end
                        txt.see(tk.END)
                        self._log_viewer_info['pos'] = fh.tell()
                except Exception:
                    pass

            def _poll():
                try:
                    if self._log_viewer_info['paused'].get():
                        # reschedule
                        self._log_viewer_info['job'] = top.after(poll_interval, _poll)
                        return
                    p = str(LOG_PATH)
                    if not os.path.exists(p):
                        self._log_viewer_info['job'] = top.after(poll_interval, _poll)
                        return
                    current_size = os.path.getsize(p)
                    pos = self._log_viewer_info.get('pos', 0) or 0
                    if current_size < pos:
                        # rotated/truncated: re-read tail
                        with open(p, 'r', encoding='utf-8', errors='ignore') as fh:
                            data = fh.read()
                            parts = data.splitlines(True)
                            last = ''.join(parts[-lines:]) if parts else ''
                            txt.configure(state='normal')
                            txt.delete('1.0', tk.END)
                            txt.insert(tk.END, last)
                            txt.configure(state='disabled')
                            txt.see(tk.END)
                            self._log_viewer_info['pos'] = fh.tell()
                    else:
                        # read appended data
                        with open(p, 'r', encoding='utf-8', errors='ignore') as fh:
                            try:
                                fh.seek(pos)
                            except Exception:
                                fh.seek(0, os.SEEK_END)
                            new = fh.read()
                            if new:
                                txt.configure(state='normal')
                                txt.insert(tk.END, new)
                                # Trim to last N lines to avoid memory growth
                                content = txt.get('1.0', tk.END)
                                parts = content.splitlines(True)
                                if len(parts) > lines * 5:
                                    trimmed = ''.join(parts[-(lines*2):])
                                    txt.delete('1.0', tk.END)
                                    txt.insert(tk.END, trimmed)
                                txt.configure(state='disabled')
                                txt.see(tk.END)
                            self._log_viewer_info['pos'] = fh.tell()
                    self._log_viewer_info['job'] = top.after(poll_interval, _poll)
                except Exception:
                    try:
                        self._log_viewer_info['job'] = top.after(poll_interval, _poll)
                    except Exception:
                        pass

            # cleanup on close
            def _on_close(event=None):
                try:
                    job = self._log_viewer_info.get('job') if self._log_viewer_info else None
                    if job:
                        try:
                            top.after_cancel(job)
                        except Exception:
                            pass
                except Exception:
                    pass
                try:
                    if hasattr(self, '_log_viewer_info'):
                        del self._log_viewer_info
                except Exception:
                    pass

            top.protocol('WM_DELETE_WINDOW', lambda: (self._safe_destroy(top)))
            top.bind('<Destroy>', _on_close)
            # initial load and start polling
            try:
                _read_initial()
            except Exception:
                pass
            try:
                self._log_viewer_info['job'] = top.after(poll_interval, _poll)
            except Exception:
                pass
        except Exception:
            pass
            # fallback: open root of file_system_root
            base = getattr(self, 'file_system_root', None) or os.getcwd()
            try:
                if sys.platform.startswith('win'):
                    os.startfile(base)
                else:
                    import subprocess
                    subprocess.Popen(['xdg-open', base])
            except Exception:
                pass
        except Exception:
            pass

    def delete_app(self, name):
        """Attempt to remove a desktop app/icon by name. Non-fatal stub."""
        try:
            # Try to remove from custom_apps and desktop icon lists
            try:
                if hasattr(self, 'custom_apps') and name in getattr(self, 'custom_apps', {}):
                    del self.custom_apps[name]
            except Exception:
                pass
            try:
                # remove icon frame if exists
                self.remove_desktop_icon(name)
            except Exception:
                pass
            # play deletion sound if available
            try:
                self.play_system_sound('delete')
            except Exception:
                pass
        except Exception:
            pass

