    def open_audio_settings(self):
        """Open the advanced audio / microphone settings window from Settings.

        Dynamically loads `forze_audio_settings.py` from the same folder so
        heavy audio deps are only required when used.
        """
        try:
            script_dir = os.path.dirname(os.path.abspath(__file__)) if '__file__' in globals() else os.getcwd()
            module_path = os.path.join(script_dir, 'forze_audio_settings.py')
            if os.path.exists(module_path):
                try:
                    import importlib.util
                    spec = importlib.util.spec_from_file_location('forze_audio_settings', module_path)
                    mod = importlib.util.module_from_spec(spec)
                    spec.loader.exec_module(mod)
                    parent = getattr(self, 'root', None)
                    try:
                        mod.AudioSettingsWindow(parent)
                    except Exception:
                        mod.AudioSettingsWindow(None)
                    return
                except Exception:
                    logger.exception('Failed to import local forze_audio_settings')
            # fallback to normal import
            try:
                import forze_audio_settings as fas
                parent = getattr(self, 'root', None)
                fas.AudioSettingsWindow(parent)
            except Exception:
                logger.exception('Failed to open audio settings via import')
                try:
                    messagebox.showerror('Audio Settings', 'Audio settings module not available.')
                except Exception:
                    pass
        except Exception:
            logger.exception('open_audio_settings error')

    def _apply_deferred_image(self, item_id, data_bytes, w, h):
        """Convert raw image bytes to a PhotoImage and apply to canvas item.

        Must be called from the Tk main thread.
        """
        try:
            if not PIL_AVAILABLE:
                return
            try:
                img = Image.open(io.BytesIO(data_bytes)).convert('RGBA')
            except Exception:
                return
            try:
                img = img.resize((w, h), Image.Resampling.LANCZOS)
            except Exception:
                pass
            try:
                photo = ImageTk.PhotoImage(img)
                self.icon_refs.append(photo)
                # Try to set the image on the existing canvas item. If that
                # fails (item isn't an image), fall back to creating a new
                # image item at the same coords and migrate metadata.
                try:
                    self.desktop_canvas.itemconfigure(item_id, image=photo)
                except Exception:
                    try:
                        coords = self.desktop_canvas.coords(item_id)
                        if coords:
                            x, y = coords[0], coords[1]
                            self.desktop_canvas.delete(item_id)
                            iid = self.desktop_canvas.create_image(x, y, image=photo, anchor='nw')
                            # migrate metadata
                            meta = self.icon_items.pop(item_id, {})
                            self.icon_items[iid] = meta
                            name = meta.get('name')
                            if name:
                                self.canvas_icons_by_name[name] = iid
                    except Exception:
                        # fallback: ignore migration failures
                        pass
            except Exception:
                # If PhotoImage creation fails, we silently ignore to avoid crashing
                pass
        except Exception:
            pass

    # === [ SECTION: Utilities / Run & Debug Helpers ] ===

    # ----------------- Run/Debug helpers -----------------
    def _ensure_runs_log(self):
        try:
            base = os.path.dirname(os.path.abspath(__file__)) if '__file__' in globals() else os.getcwd()
            log_dir = os.path.join(base, 'forzeos_logs')
            os.makedirs(log_dir, exist_ok=True)
            self._runs_log_path = os.path.join(log_dir, 'runs.json')
            if not os.path.exists(self._runs_log_path):
                with open(self._runs_log_path, 'w', encoding='utf-8') as fh:
                    json.dump([], fh)
        except Exception:
            self._runs_log_path = None

    def _append_run_log(self, entry: dict):
        try:
            if not hasattr(self, '_runs_log_path') or not self._runs_log_path:
                self._ensure_runs_log()
            if not self._runs_log_path:
                return
            # load, append, save
            try:
                with open(self._runs_log_path, 'r', encoding='utf-8') as fh:
                    data = json.load(fh)
            except Exception:
                data = []
            data.append(entry)
            with open(self._runs_log_path, 'w', encoding='utf-8') as fh:
                json.dump(data, fh, ensure_ascii=False, indent=2)
        except Exception:
            pass

    def _safe_spawn_process(self, cmd_list, cwd=None, run_type='normal', window=None, env=None, creationflags=0):
        """Spawn a subprocess safely (non-shell). Returns popen or raises."""
        try:
            if sys.platform.startswith('win'):
                # Use CREATE_NEW_CONSOLE so GUI apps show on taskbar when appropriate
                CREATE_NEW_CONSOLE = 0x00000010
                flags = creationflags or CREATE_NEW_CONSOLE
            else:
                flags = creationflags or 0

            popen = subprocess.Popen(list(cmd_list), stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                                     stdin=subprocess.PIPE, text=True, shell=False, cwd=cwd, env=env,
                                     creationflags=flags)

            # record process metadata
            meta = {
                'cmdline': ' '.join(cmd_list),
                'cwd': cwd or os.getcwd(),
                'user': getpass.getuser(),
                'start_time': datetime.datetime.now().isoformat(),
                'run_type': run_type
            }

            if window is not None:
                window._processes[popen.pid] = {'popen': popen, 'meta': meta, 'cmdline': meta['cmdline']}
                try:
                    window._refresh_proc_list()
                except Exception:
                    pass

            # Start threads to stream stdout/stderr
            threading.Thread(target=lambda: self._stream_process_output(popen, window), daemon=True).start()

            # Append audit log (minimal stdout/stderr snapshot will be appended on exit)
            entry = {'user': meta['user'], 'cmd': meta['cmdline'], 'cwd': meta['cwd'], 'run_type': run_type,
                     'start_time': meta['start_time'], 'pid': popen.pid}
            self._append_run_log(entry)

            return popen
        except Exception as e:
            raise

    def _stream_process_output(self, popen: subprocess.Popen, window=None):
        """Read stdout/stderr in real time and append to editor console; when process exits, update logs."""
        try:
            out_lines = []
            err_lines = []

            def drain_stream(stream, collector, tag=None):
                try:
                    for line in iter(stream.readline, ''):
                        if not line:
                            break
                        collector.append(line)
                        if window and hasattr(window, 'console'):
                            try:
                                window.console.insert(tk.END, line)
                                window.console.see(tk.END)
                            except Exception:
                                pass
                except Exception:
                    pass

            t_out = threading.Thread(target=drain_stream, args=(popen.stdout, out_lines, 'stdout'), daemon=True)
            t_err = threading.Thread(target=drain_stream, args=(popen.stderr, err_lines, 'stderr'), daemon=True)
            t_out.start(); t_err.start()

            # Wait for process to finish
            ret = popen.wait()

            # ensure drains finished
            try:
                t_out.join(timeout=1)
            except Exception:
                pass
            try:
                t_err.join(timeout=1)
            except Exception:
                pass

            # Update process list
            try:
                if window and popen.pid in window._processes:
                    window._processes[popen.pid]['popen'] = popen
                    window._refresh_proc_list()
            except Exception:
                pass

            # Update audit log entry with exit code and small stdout/stderr snapshot
            try:
                snap_out = ''.join(out_lines[-50:]) if out_lines else ''
                snap_err = ''.join(err_lines[-50:]) if err_lines else ''
                entry = {'pid': popen.pid, 'exit_code': ret, 'stdout': snap_out, 'stderr': snap_err,
                         'end_time': datetime.datetime.now().isoformat()}
                # Append to runs log
                try:
                    if hasattr(self, '_runs_log_path') and self._runs_log_path:
                        with open(self._runs_log_path, 'r', encoding='utf-8') as fh:
                            data = json.load(fh)
                except Exception:
                    data = []
                # Try to find original entry by pid and update, otherwise append
                updated = False
                for e in data:
                    if e.get('pid') == popen.pid and 'end_time' not in e:
                        e.update(entry)
                        updated = True
                        break
                if not updated:
                    data.append(entry)
                if hasattr(self, '_runs_log_path') and self._runs_log_path:
                    with open(self._runs_log_path, 'w', encoding='utf-8') as fh:
                        json.dump(data, fh, ensure_ascii=False, indent=2)
            except Exception:
                pass

        except Exception:
            pass

    def _stop_process_from_window(self, window):
        try:
            if not window or not hasattr(window, '_processes'):
                return
            selection = window.processes_list.curselection()
            if not selection:
                # try stopping the last process
                pids = list(window._processes.keys())
                if not pids:
                    return
                pid = pids[-1]
            else:
                text = window.processes_list.get(selection[0])
                pid = int(re.search(r'PID\s*(\d+)', text).group(1)) if re.search(r'PID\s*(\d+)', text) else None
            if not pid:
                return
            info = window._processes.get(pid)
            if not info:
                return
            popen = info.get('popen')
            if popen and popen.poll() is None:
                try:
                    popen.terminate()
                    # give graceful time then kill
                    def killer(p):
                        try:
                            p.wait(timeout=3)
                        except Exception:
                            try:
                                p.kill()
                            except Exception:
                                pass
                    threading.Thread(target=killer, args=(popen,), daemon=True).start()
                except Exception:
                    try:
                        popen.kill()
                    except Exception:
                        pass
            # update list
            try:
                window._refresh_proc_list()
            except Exception:
                pass
            # audit
            try:
                self._append_run_log({'pid': pid, 'action': 'terminated', 'time': datetime.datetime.now().isoformat(), 'user': getpass.getuser()})
            except Exception:
                pass
        except Exception:
            pass

    def _toggle_process_panel(self, window):
        try:
            if not window:
                return
            if window.processes_frame.winfo_ismapped():
                window.processes_frame.pack_forget()
            else:
                window.processes_frame.pack(fill=tk.BOTH, padx=5)
                try:
                    window._refresh_proc_list()
                except Exception:
                    pass
        except Exception:
            pass

    def _run_as_admin_prompt(self, cmd_list):
        """Show a user confirmation dialog for running as admin. Returns True if allowed."""
        try:
            return messagebox.askyesno('Run as Administrator',
                                      'This action will run the program with administrator privileges. Continue?')
        except Exception:
            return False

    def _start_debug_session(self, window, python_exe, tmpfile_path, port=5678):
        """Start debugpy listeners and spawn process under debugpy; returns popen"""
        try:
            # Ensure debugpy is available; if not, inform user how to install
            try:
                import debugpy
                debugpy_available = True
            except Exception:
                debugpy_available = False
            if not debugpy_available:
                if messagebox.askyesno('debugpy missing', 'debugpy is required for debugging. Install via pip now?'):
                    try:
                        subprocess.check_call([python_exe, '-m', 'pip', 'install', 'debugpy'])
                        import debugpy
                        debugpy_available = True
                    except Exception as e:
                        messagebox.showerror('Install failed', f'Could not install debugpy: {e}')
                        return None

            # Launch python with debugpy as a module to listen for connections
            # We use --listen to have the debug server in the child and connect back to editor
            cmd = [python_exe, '-m', 'debugpy', '--listen', f'127.0.0.1:{port}', tmpfile_path]
            popen = self._safe_spawn_process(cmd, run_type='debug', window=window)
            # Inform user to connect (editor-side client not implemented fully here)
            try:
                window.console.insert(tk.END, f"Debug server started on 127.0.0.1:{port} (PID {popen.pid})\n")
                window.console.see(tk.END)
            except Exception:
                pass
            return popen
        except Exception:
            return None

        
