    def decrypt_file(self):
        """Decrypt selected file"""
        try:
            if not self.selected_file_path:
                messagebox.showerror("Error", "Please select a file first")
                return
            
            password = self.encrypt_password_entry.get()
            if not password:
                messagebox.showerror("Error", "Please enter decryption password")
                return
            
            # Generate key from password
            import hashlib
            key = hashlib.sha256(password.encode()).digest()
            fernet = Fernet(key[:32].hex()[:44] + '=')
            
            # Read encrypted file
            with open(self.selected_file_path, 'rb') as f:
                encrypted_data = f.read()
            
            # Decrypt data
            decrypted_data = fernet.decrypt(encrypted_data)
            
            # Save decrypted file
            if self.selected_file_path.endswith('.enc'):
                output_path = self.selected_file_path[:-4]  # Remove .enc extension
            else:
                output_path = self.selected_file_path + '.decrypted'
            
            with open(output_path, 'wb') as f:
                f.write(decrypted_data)
            
            self.encrypt_status.insert(tk.END, f"✓ File decrypted successfully!\n")
            self.encrypt_status.insert(tk.END, f"Encrypted: {self.selected_file_path}\n")
            self.encrypt_status.insert(tk.END, f"Decrypted: {output_path}\n\n")
            self.encrypt_status.see(tk.END)
            
            messagebox.showinfo("Success", f"File decrypted successfully!\nSaved as: {output_path}")
            
        except Exception as e:
            messagebox.showerror("Error", f"Decryption failed: {e}")

    # ------------------ ForzeVault helpers (simple Fernet-based vault) ------------------
    def generate_vault_key(self):
        """Generate a fresh Fernet key (bytes)."""
        try:
            if not CRYPTO_AVAILABLE:
                messagebox.showerror("Error", "Encryption support requires cryptography library.\nInstall with: pip install cryptography")
                return None
            return Fernet.generate_key()
        except Exception as e:
            try:
                logger.exception("generate_vault_key failed")
            except Exception:
                pass
            messagebox.showerror("Error", f"Failed to generate key: {e}")
            return None

    def generate_vault_key_from_password(self, password: str, salt: bytes = None, iterations: int = 200000):
        """Derive a 32-byte Fernet-compatible key from a password using PBKDF2-HMAC-SHA256.

        Returns urlsafe_b64-encoded key bytes suitable for Fernet.
        """
        try:
            if not CRYPTO_AVAILABLE:
                messagebox.showerror("Error", "Encryption support requires cryptography library.\nInstall with: pip install cryptography")
                return None
            import hashlib, base64, os
            if salt is None:
                # store/serialize salt externally if persistent derivation is needed
                salt = b'ForzeOS_vault_salt'  # conservative default (user may provide stronger)
            key = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, int(iterations), dklen=32)
            return base64.urlsafe_b64encode(key)
        except Exception as e:
            try:
                logger.exception("generate_vault_key_from_password failed")
            except Exception:
                pass
            messagebox.showerror("Error", f"Key derivation failed: {e}")
            return None

    def vault_encrypt_file(self, src_path: str, key: bytes, out_path: str = None, remove_original: bool = False):
        """Encrypt a file using a Fernet key (bytes). Returns output path or None on error."""
        try:
            if not CRYPTO_AVAILABLE:
                messagebox.showerror("Error", "Encryption support requires cryptography library.\nInstall with: pip install cryptography")
                return None
            import base64
            if not key:
                messagebox.showerror("Error", "No encryption key provided")
                return None
            if not os.path.exists(src_path):
                messagebox.showerror("Error", f"Source not found: {src_path}")
                return None
            if out_path is None:
                out_path = src_path + '.fvault'
            # Accept either raw Fernet key or urlsafe_b64 bytes
            try:
                f = Fernet(key)
            except Exception:
                # try treating key as passphrase-derived bytes
                try:
                    import base64
                    if isinstance(key, str):
                        key = key.encode()
                    k = key
                    f = Fernet(k)
                except Exception:
                    messagebox.showerror("Error", "Invalid Fernet key")
                    return None

            with open(src_path, 'rb') as rf:
                data = rf.read()
            token = f.encrypt(data)
            with open(out_path, 'wb') as wf:
                wf.write(token)
            try:
                logger.info("vault_encrypt_file: encrypted %s -> %s", src_path, out_path)
            except Exception:
                pass
            if remove_original:
                try:
                    os.remove(src_path)
                except Exception:
                    pass
            return out_path
        except Exception as e:
            try:
                logger.exception("vault_encrypt_file failed")
            except Exception:
                pass
            messagebox.showerror("Error", f"Encryption failed: {e}")
            return None

    def vault_decrypt_file(self, enc_path: str, key: bytes, out_path: str = None, remove_encrypted: bool = False):
        """Decrypt a Fernet-encrypted file. Returns output path or None on error."""
        try:
            if not CRYPTO_AVAILABLE:
                messagebox.showerror("Error", "Encryption support requires cryptography library.\nInstall with: pip install cryptography")
                return None
            if not os.path.exists(enc_path):
                messagebox.showerror("Error", f"Encrypted file not found: {enc_path}")
                return None
            if out_path is None:
                if enc_path.endswith('.fvault'):
                    out_path = enc_path[:-7]
                elif enc_path.endswith('.enc'):
                    out_path = enc_path[:-4]
                else:
                    out_path = enc_path + '.decrypted'

            try:
                f = Fernet(key)
            except Exception:
                try:
                    if isinstance(key, str):
                        key = key.encode()
                    f = Fernet(key)
                except Exception:
                    messagebox.showerror("Error", "Invalid Fernet key")
                    return None

            with open(enc_path, 'rb') as rf:
                token = rf.read()
            data = f.decrypt(token)
            with open(out_path, 'wb') as wf:
                wf.write(data)
            try:
                logger.info("vault_decrypt_file: decrypted %s -> %s", enc_path, out_path)
            except Exception:
                pass
            if remove_encrypted:
                try:
                    os.remove(enc_path)
                except Exception:
                    pass
            return out_path
        except Exception as e:
            try:
                logger.exception("vault_decrypt_file failed")
            except Exception:
                pass
            messagebox.showerror("Error", f"Decryption failed: {e}")
            return None

