    def scan_local_network(self):
        """Scan local network for devices"""
        try:
            # Non-blocking threaded scan using TCP connect and fallback to ping
            try:
                self.network_results.delete('1.0', tk.END)
            except Exception:
                pass
            self.network_results.insert(tk.END, "\n=== SCANNING LOCAL NETWORK ===\n")
            self.network_results.insert(tk.END, "Scanning for active devices... (this may take a while)\n\n")
            self.network_results.see(tk.END)

            def _get_local_ip():
                try:
                    s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
                    s.settimeout(0.5)
                    try:
                        s.connect(('8.8.8.8', 80))
                        ip = s.getsockname()[0]
                    finally:
                        try:
                            s.close()
                        except Exception:
                            pass
                    if not ip or ip.startswith('127.'):
                        # fallback to hostname
                        try:
                            ip = socket.gethostbyname(socket.gethostname())
                        except Exception:
                            ip = '127.0.0.1'
                    return ip
                except Exception:
                    try:
                        return socket.gethostbyname(socket.gethostname())
                    except Exception:
                        return '127.0.0.1'

            local_ip = _get_local_ip()
            try:
                base_parts = local_ip.split('.')[:3]
                network_base = '.'.join(base_parts)
            except Exception:
                network_base = '.'.join(local_ip.split('.')[:-1])

            self.network_results.insert(tk.END, f"Network Base: {network_base}.x\n")
            self.network_results.insert(tk.END, f"Local IP: {local_ip}\n\n")
            self.network_results.see(tk.END)

            import threading, concurrent.futures, subprocess, platform, time

            ips = [f"{network_base}.{i}" for i in range(1, 255)]
            ports = [80, 443, 22, 139, 445]

            found = []
            total = len(ips)
            completed = 0

            stop_event = threading.Event()

            def probe(ip):
                # Return a tuple (ip, alive, info)
                try:
                    for p in ports:
                        try:
                            sock = socket.create_connection((ip, p), timeout=0.5)
                            sock.close()
                            return (ip, True, f"open port {p}")
                        except Exception:
                            pass
                    # Fallback to platform ping
                    try:
                        param = '-n' if platform.system().lower().startswith('win') else '-c'
                        # timeout param differs; -w on Windows (milliseconds), -W on unix (seconds)
                        if platform.system().lower().startswith('win'):
                            proc = subprocess.run(['ping', param, '1', '-w', '1000', ip], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
                        else:
                            proc = subprocess.run(['ping', param, '1', '-W', '1', ip], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
                        if proc.returncode == 0:
                            return (ip, True, 'ping')
                    except Exception:
                        pass
                except Exception:
                    pass
                return (ip, False, '')

            def _run_scan():
                nonlocal completed
                try:
                    with concurrent.futures.ThreadPoolExecutor(max_workers=100) as ex:
                        futures = {ex.submit(probe, ip): ip for ip in ips}
                        for fut in concurrent.futures.as_completed(futures):
                            try:
                                ip, alive, info = fut.result()
                            except Exception:
                                ip, alive, info = (futures.get(fut, 'unknown'), False, '')
                            completed += 1
                            if alive:
                                # try reverse DNS
                                host = ip
                                try:
                                    host = socket.gethostbyaddr(ip)[0]
                                except Exception:
                                    pass
                                found.append((ip, host, info))
                                # update UI incrementally
                                try:
                                    self.root.after(0, lambda ip=ip, host=host, info=info: self.network_results.insert(tk.END, f"Found: {ip} - {host} ({info})\n"))
                                except Exception:
                                    pass
                            # Update progress occasionally
                            if completed % 10 == 0 or completed == total:
                                try:
                                    self.root.after(0, lambda c=completed, t=total: self.network_results.insert(tk.END, f"Progress: {c}/{t}\n"))
                                except Exception:
                                    pass
                    # Final summary
                    try:
                        self.root.after(0, lambda: self.network_results.insert(tk.END, f"\nScan complete. Found {len(found)} devices.\n"))
                        self.root.after(0, lambda: self.network_results.see(tk.END))
                    except Exception:
                        pass
                except Exception as e:
                    try:
                        self.root.after(0, lambda: self.network_results.insert(tk.END, f"Scan error: {e}\n"))
                    except Exception:
                        pass

            # Run scanning in background thread so UI is not blocked
            try:
                t = threading.Thread(target=_run_scan, daemon=True)
                t.start()
            except Exception as e:
                try:
                    self.network_results.insert(tk.END, f"Failed to start scan thread: {e}\n")
                except Exception:
                    pass

        except Exception as e:
            try:
                self.network_results.insert(tk.END, f"Error: {e}\n")
            except Exception:
                pass

    def get_network_info(self):
        """Get network information"""
        try:
            self.network_results.insert(tk.END, "\n=== NETWORK INFORMATION ===\n")
            
            # Basic network info
            hostname = socket.gethostname()
            local_ip = socket.gethostbyname(hostname)
            
            self.network_results.insert(tk.END, f"Hostname: {hostname}\n")
            self.network_results.insert(tk.END, f"Local IP: {local_ip}\n")
            
            # Network interfaces using psutil
            interfaces = psutil.net_if_addrs()
            self.network_results.insert(tk.END, f"\nNetwork Interfaces:\n")
            for interface, addresses in interfaces.items():
                self.network_results.insert(tk.END, f"  {interface}:\n")
                for addr in addresses:
                    self.network_results.insert(tk.END, f"    {addr.family.name}: {addr.address}\n")
            
            # Network statistics
            net_stats = psutil.net_io_counters()
            self.network_results.insert(tk.END, f"\nNetwork Statistics:\n")
            self.network_results.insert(tk.END, f"  Bytes Sent: {net_stats.bytes_sent:,}\n")
            self.network_results.insert(tk.END, f"  Bytes Received: {net_stats.bytes_recv:,}\n")
            self.network_results.insert(tk.END, f"  Packets Sent: {net_stats.packets_sent:,}\n")
            self.network_results.insert(tk.END, f"  Packets Received: {net_stats.packets_recv:,}\n")
            
            self.network_results.see(tk.END)
            
        except Exception as e:
            self.network_results.insert(tk.END, f"Error getting network info: {e}\n")

    def network_speed_test(self):
        """Simple network speed test"""
        try:
            self.network_results.insert(tk.END, "\n=== NETWORK SPEED TEST ===\n")
            self.network_results.insert(tk.END, "Testing connection speed...\n")
            # Run the potentially blocking parts in a background thread
            def _worker():
                try:
                    import time
                    start_time = time.time()
                    latency = None

                    try:
                        socket.create_connection(("8.8.8.8", 53), timeout=3)
                        end_time = time.time()
                        latency = (end_time - start_time) * 1000
                    except Exception:
                        latency = None

                    # Download test using urllib but off the main thread
                    download_speed = 0
                    try:
                        import urllib.request
                        url = 'https://www.google.com/images/branding/googlelogo/2x/googlelogo_color_272x92dp.png'
                        dl_start = time.time()
                        urllib.request.urlretrieve(url, 'temp_image.png')
                        dl_end = time.time()
                        file_size = os.path.getsize('temp_image.png')
                        if dl_end - dl_start > 0:
                            download_speed = file_size / (dl_end - dl_start) / 1024
                        try:
                            os.remove('temp_image.png')
                        except Exception:
                            pass
                    except Exception as e:
                        download_speed = 0
                        self.root.after(0, lambda: self.terminal_output.insert(tk.END, f"Download test failed: {e}\n"))

                    # Simulated upload test
                    upload_speed = random.randint(5, 50)

                    # Prepare formatted results and push to UI on main thread
                    def _apply():
                        try:
                            if latency is not None:
                                self.network_results.insert(tk.END, f"Ping to 8.8.8.8: {latency:.2f} ms\n")
                            else:
                                self.network_results.insert(tk.END, "Ping: failed\n")
                            download_est = random.randint(10, 100) if download_speed == 0 else int(download_speed/1024)
                            self.network_results.insert(tk.END, f"Estimated Download Speed: {download_est} Mbps\n")
                            self.network_results.insert(tk.END, f"Estimated Upload Speed: {upload_speed} Mbps\n")
                            if latency is not None:
                                if latency < 50:
                                    quality = "Excellent"
                                elif latency < 100:
                                    quality = "Good"
                                else:
                                    quality = "Poor"
                            else:
                                quality = "Unknown"
                            self.network_results.insert(tk.END, f"Connection Quality: {quality}\n")
                            self.network_results.see(tk.END)
                        except Exception:
                            pass

                    self.root.after(0, _apply)

                except Exception as e:
                    try:
                        self.root.after(0, lambda: self.network_results.insert(tk.END, f"Connection test failed: {e}\n"))
                    except Exception:
                        pass

            threading.Thread(target=_worker, daemon=True).start()

        except Exception as e:
            self.network_results.insert(tk.END, f"Speed test error: {e}\n")

