    def ttt_make_move(self, row, col):
        """Make a move in Tic-Tac-Toe"""
        if self.ttt_game_over or self.ttt_board[row][col] != '':
            return
        
        # Make move
        self.ttt_board[row][col] = self.ttt_current_player
        self.ttt_buttons[row][col].config(text=self.ttt_current_player,
                                         fg='red' if self.ttt_current_player == 'X' else 'blue')
        
        # Check for win
        if self.ttt_check_winner():
            self.ttt_status_label.config(text=f"Player {self.ttt_current_player} wins!")
            self.ttt_game_over = True
            messagebox.showinfo("Game Over", f"Player {self.ttt_current_player} wins!")
        elif self.ttt_board_full():
            self.ttt_status_label.config(text="It's a tie!")
            self.ttt_game_over = True
            messagebox.showinfo("Game Over", "It's a tie!")
        else:
            # Switch player
            self.ttt_current_player = 'O' if self.ttt_current_player == 'X' else 'X'
            self.ttt_status_label.config(text=f"Player {self.ttt_current_player}'s turn")

    def ttt_check_winner(self):
        """Check for Tic-Tac-Toe winner"""
        # Check rows
        for row in self.ttt_board:
            if row[0] == row[1] == row[2] != '':
                return True
        
        # Check columns
        for col in range(3):
            if self.ttt_board[0][col] == self.ttt_board[1][col] == self.ttt_board[2][col] != '':
                return True
        
        # Check diagonals
        if self.ttt_board[0][0] == self.ttt_board[1][1] == self.ttt_board[2][2] != '':
            return True
        if self.ttt_board[0][2] == self.ttt_board[1][1] == self.ttt_board[2][0] != '':
            return True
        
        return False

    def ttt_board_full(self):
        """Check if Tic-Tac-Toe board is full"""
        for row in self.ttt_board:
            for cell in row:
                if cell == '':
                    return False
        return True

