    def fb_start_game(self):
        """Start Flappy Bird game"""
        self.fb_bird_y = 250
        self.fb_bird_velocity = 0
        self.fb_pipes = []
        self.fb_score = 0
        self.fb_game_running = True
        self.fb_score_label.config(text=f"Score: {self.fb_score}")
        self.fb_game_loop()

    def fb_jump(self):
        """Make bird jump"""
        if self.fb_game_running:
            self.fb_bird_velocity = self.fb_jump_strength

    def fb_game_loop(self):
        """Main Flappy Bird game loop"""
        if not self.fb_game_running:
            return
        
        try:
            # Update bird
            self.fb_bird_velocity += self.fb_gravity
            self.fb_bird_y += self.fb_bird_velocity
            
            # Check boundaries
            if self.fb_bird_y < 0 or self.fb_bird_y > 470:
                self.fb_game_over()
                return
            
            # Update pipes
            if len(self.fb_pipes) == 0 or self.fb_pipes[-1]['x'] < 200:
                gap_y = random.randint(100, 300)
                self.fb_pipes.append({
                    'x': 400,
                    'gap_y': gap_y,
                    'passed': False
                })
            
            # Move pipes
            for pipe in self.fb_pipes[:]:
                pipe['x'] -= 3
                
                # Check collision
                if (50 < pipe['x'] < 80 and 
                    (self.fb_bird_y < pipe['gap_y'] - 75 or self.fb_bird_y > pipe['gap_y'] + 75)):
                    self.fb_game_over()
                    return
                
                # Score
                if not pipe['passed'] and pipe['x'] < 50:
                    pipe['passed'] = True
                    self.fb_score += 1
                    self.fb_score_label.config(text=f"Score: {self.fb_score}")
                
                # Remove off-screen pipes
                if pipe['x'] < -60:
                    self.fb_pipes.remove(pipe)
            
            self.fb_draw_game()
            self.fb_window.after(20, self.fb_game_loop)
            
        except Exception as e:
            print(f"Flappy Bird loop error: {e}")

    def fb_draw_game(self):
        """Draw Flappy Bird game"""
        try:
            self.fb_canvas.delete("all")
            
            # Draw bird
            self.fb_canvas.create_oval(40, self.fb_bird_y, 70, self.fb_bird_y + 30, fill='yellow', outline='orange')
            
            # Draw pipes
            for pipe in self.fb_pipes:
                # Top pipe
                self.fb_canvas.create_rectangle(pipe['x'], 0, pipe['x'] + 60, pipe['gap_y'] - 75, 
                                              fill='green', outline='darkgreen')
                # Bottom pipe
                self.fb_canvas.create_rectangle(pipe['x'], pipe['gap_y'] + 75, pipe['x'] + 60, 500, 
                                              fill='green', outline='darkgreen')
            
        except Exception as e:
            print(f"Draw Flappy Bird error: {e}")

    def fb_game_over(self):
        """Handle Flappy Bird game over"""
        self.fb_game_running = False
        messagebox.showinfo("Game Over", f"Game Over! Final Score: {self.fb_score}")

