    def math_calculate(self):
        """Calculate mathematical expression"""
        try:
            expression = self.math_expression.get()
            if not expression:
                return
            
            # Safe evaluation
            import math
            allowed_names = {
                'sin': math.sin, 'cos': math.cos, 'tan': math.tan,
                'asin': math.asin, 'acos': math.acos, 'atan': math.atan,
                'sinh': math.sinh, 'cosh': math.cosh, 'tanh': math.tanh,
                'log': math.log, 'log10': math.log10, 'log2': math.log2,
                'exp': math.exp, 'sqrt': math.sqrt, 'pow': pow,
                'pi': math.pi, 'e': math.e, 'abs': abs,
                'floor': math.floor, 'ceil': math.ceil, 'round': round
            }
            
            result = eval(expression, {"__builtins__": {}}, allowed_names)
            
            self.math_result.insert(tk.END, f"Expression: {expression}\n")
            self.math_result.insert(tk.END, f"Result: {result}\n\n")
            self.math_result.see(tk.END)
            
        except Exception as e:
            self.math_result.insert(tk.END, f"Error: {e}\n\n")
            self.math_result.see(tk.END)

    def math_plot_function(self):
        """Plot mathematical function"""
        try:
            function_str = self.math_function.get()
            x_min = float(self.math_x_min.get())
            x_max = float(self.math_x_max.get())
            
            # Create x values
            x = np.linspace(x_min, x_max, 1000)
            
            # Safe evaluation
            import math
            allowed_names = {
                'sin': np.sin, 'cos': np.cos, 'tan': np.tan,
                'log': np.log, 'log10': np.log10, 'sqrt': np.sqrt,
                'exp': np.exp, 'pi': math.pi, 'e': math.e,
                'abs': np.abs, 'x': x
            }
            
            # Evaluate function
            y = eval(function_str, {"__builtins__": {}}, allowed_names)
            
            # Clear and plot
            self.math_subplot.clear()
            self.math_subplot.plot(x, y, 'b-', linewidth=2)
            self.math_subplot.grid(True)
            self.math_subplot.set_xlabel('x')
            self.math_subplot.set_ylabel('f(x)')
            self.math_subplot.set_title(f'f(x) = {function_str}')
            
            self.math_canvas.draw()
            
        except Exception as e:
            messagebox.showerror("Error", f"Plot error: {e}")

    def _atomic_write_json(self, path, data):
        """Atomically write JSON to `path`. Returns (success:bool, backup_path or None)."""
        try:
            import tempfile, shutil, time, json
            try:
                ddir = os.path.dirname(os.path.abspath(path)) or os.getcwd()
            except Exception:
                ddir = os.getcwd()
            ts = int(time.time())
            backup = f"{path}.bak.{ts}"
            try:
                if os.path.exists(path):
                    shutil.copy2(path, backup)
                    logger.info('Created config backup %s', backup)
            except Exception:
                logger.exception('Failed creating config backup')
            fd, tmp = tempfile.mkstemp(prefix='forzeos_config_', suffix='.tmp', dir=ddir)
            try:
                with os.fdopen(fd, 'w', encoding='utf-8') as fh:
                    json.dump(data, fh, ensure_ascii=False, indent=2)
                os.replace(tmp, path)
                return True, backup
            except Exception:
                try:
                    os.remove(tmp)
                except Exception:
                    pass
                logger.exception('Atomic write failed for %s', path)
                return False, backup
        except Exception:
            logger.exception('Unexpected error in _atomic_write_json')
            return False, None

    def _verify_image_file(self, path):
        """Return (ok:bool, message) validating image can be opened and read."""
        try:
            if not path or not os.path.exists(path):
                return False, 'Dosya bulunamadı'
            if not PIL_AVAILABLE:
                return False, 'Pillow (PIL) mevcut değil'
            im = Image.open(path).convert('RGBA')
            w, h = im.size
            return True, f'{w}x{h}'
        except Exception as e:
            logger.exception('Image verification failed for %s', path)
            return False, str(e)

    def _backup_config(self):
        try:
            import time, shutil
            cfg_path = getattr(self, 'config_file', 'forzeos_config.json')
            ts = int(time.time())
            bak = f"{cfg_path}.bak.{ts}"
            try:
                if os.path.exists(cfg_path):
                    shutil.copy2(cfg_path, bak)
                    return bak
            except Exception:
                logger.exception('Failed to create config backup')
            return None
        except Exception:
            return None

    def _test_login_image_load(self):
        try:
            cfg = self.config.setdefault('settings', {})
            p = cfg.get('login_panel_image') or os.path.join(os.path.dirname(__file__), 'ForzeOS_LOGIN.png')
            ok, msg = self._verify_image_file(p)
            logger.info('Login image test: %s %s', ok, msg)
            return ok, msg
        except Exception as e:
            logger.exception('Login image test failed')
            return False, str(e)

    def _reload_login_panel(self):
        try:
            if not getattr(self, 'login_window', None) or not getattr(self, 'login_window', None).winfo_exists():
                return False
            try:
                # Attempt to clear previous items
                if hasattr(self, '_login_panel_id') and self._login_panel_id:
                    try:
                        self.login_canvas.delete(self._login_panel_id)
                    except Exception:
                        pass
            except Exception:
                pass
            try:
                for wid in getattr(self, '_login_canvas_window_ids', [])[:]:
                    try:
                        self.login_canvas.delete(wid)
                    except Exception:
                        pass
                self._login_canvas_window_ids = []
            except Exception:
                pass
            # Cleanly destroy existing login window and recreate it so new
            # configuration (images, overlays) is applied without stale state.
            try:
                # call cleanup if available
                try:
                    if hasattr(self, '_login_cleanup') and callable(self._login_cleanup):
                        try:
                            self._login_cleanup()
                        except Exception:
                            pass
                except Exception:
                    pass
                try:
                    if getattr(self, 'login_window', None) and getattr(self, 'login_window', None).winfo_exists():
                        try:
                            self.login_window.destroy()
                        except Exception:
                            try:
                                self.login_window.withdraw()
                            except Exception:
                                pass
                except Exception:
                    pass
                # Now recreate fresh
                try:
                    self.show_login()
                    return True
                except Exception:
                    logger.exception('Failed to reload login via fresh show_login')
                    return False
            except Exception:
                logger.exception('Failed to cleanly recreate login window')
                return False
        except Exception:
            logger.exception('Unexpected error during _reload_login_panel')
            return False

    def _apply_login_panel_from_config(self):
        """Legacy shim: call show_login and let it draw using config (convenience)."""
        try:
            # If login window exists, redraw it
            if getattr(self, 'login_window', None) and getattr(self, 'login_window', None).winfo_exists():
                return self._reload_login_panel()
            # otherwise create new login
            self.show_login()
            return True
        except Exception:
            logger.exception('Failed to apply login panel from config')
            return False

