                ll_var = tk.StringVar(value=str(s_cfg.get('loading_logo_image') or ''))
                llogo_var = tk.StringVar(value=str(s_cfg.get('login_logo_image') or ''))
                login_sound_var = tk.StringVar(value=str(s_cfg.get('login_sound') or ''))
                loading_sound_var = tk.StringVar(value=str(s_cfg.get('loading_sound') or ''))
