                scale_disp = tk.Label(sa_row, text=f"{scale_var.get():.2f}", bg=self.colors['bg'], fg=self.colors['fg'], width=6)
                scale_disp.pack(side=tk.LEFT, padx=(6,4))
                scale_w = tk.Scale(sa_row, variable=scale_var, from_=0.5, to=2.0, resolution=0.01, orient=tk.HORIZONTAL, length=260, bg=self.colors['bg'])
