                tk.Spinbox(margin_row, from_=0, to=300, width=6, textvariable=margin_y_var).pack(side=tk.LEFT, padx=(2,6))

                tk.Checkbutton(settings_section, text='Auto-arrange windows on open', variable=auto_win_var, bg=self.colors['bg'], fg=self.colors['fg']).pack(anchor='w', pady=(6,0))
                tk.Checkbutton(settings_section, text='Auto-run arrange on desktop refresh/login', variable=auto_login_var, bg=self.colors['bg'], fg=self.colors['fg']).pack(anchor='w')

                # arrangement mode selector
                mode_row = tk.Frame(settings_section, bg=self.colors['bg'])
