            tk.Label(left_inner, text="Cursor Appearance", bg=self.colors['bg'], fg=self.colors['fg'], font=('Segoe UI', 12, 'bold')).pack(anchor='w', pady=(4,6), padx=6)

            # Cursor shape selector (radio buttons for clarity)
            cursor_var = tk.StringVar(value=mouse_cfg.get('cursor','arrow'))
            tk.Label(left_inner, text='Cursor shape:', bg=self.colors['bg'], fg=self.colors['fg']).pack(anchor='w', padx=6)
            shapes_frame = tk.Frame(left_inner, bg=self.colors['bg'])
