            tk.Label(left_inner, text='Cursor theme (name):', bg=self.colors['bg'], fg=self.colors['fg']).pack(anchor='w', padx=6, pady=(8,0))
            theme_var = tk.StringVar(value=mouse_cfg.get('cursor_theme','default'))
